/**
 * Dual-Handed Assault (Fighter 4, 1 action)
 * Strike with one-handed weapon using two hands for an extra damage die.
 */
export function resolveDualHandedAssault(ctx: FeatActionContext, actor: Creature, gameState: GameState, weaponId?: string, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Dual-Handed Assault') && !ctx.hasFeat(actor, 'Dual Handed Assault')) {
    return { success: false, message: `${actor.name} does not have Dual-Handed Assault.` , errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  // Resolve the Strike normally
  const strikeResult = ctx.resolveAttackAction(actor, gameState, targetId, weaponId, { isVicious: false }, heroPointsSpent);
  if (!strikeResult.success) return strikeResult;

  // On hit, add an extra weapon damage die
  if (strikeResult.details?.result === 'success' || strikeResult.details?.result === 'critical-success') {
    const selectedWeapon = ctx.getSelectedWeapon(actor, weaponId);
    const baseFormula = selectedWeapon?.damageDice ?? actor.weaponDamageDice ?? '1d4';
    const dieMatch = baseFormula.match(/(\d+)d(\d+)/i);
    const dieSides = dieMatch ? parseInt(dieMatch[2], 10) : 6;
    const extraRoll = rollDamageFormula(`1d${dieSides}`);
    const extraDamage = strikeResult.details?.result === 'critical-success' ? extraRoll.total * 2 : extraRoll.total;
    
    // Apply extra damage to target
    const target = gameState.creatures.find(c => c.id === targetId);
    if (target) {
      target.currentHealth -= extraDamage;
    }
    strikeResult.message += ` ÃƒÂ°Ã…Â¸Ã¢â‚¬â„¢Ã‚Âª Two-handed grip adds ${extraDamage} extra damage!`;
  }
  return strikeResult;
}

