/**
 * Certain Strike (Fighter 10, 1 action, Press)
 * Strike; if you miss, deal minimum damage (each die = 1).
 */
export function resolveCertainStrike(ctx: FeatActionContext, actor: Creature, gameState: GameState, weaponId?: string, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Certain Strike')) {
    return { success: false, message: `${actor.name} does not have Certain Strike.` , errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  const strikeResult = ctx.resolveAttackAction(actor, gameState, targetId, weaponId, { isVicious: false }, heroPointsSpent);

  // On a miss (failure), deal minimum damage (each die treated as 1)
  if (strikeResult.details?.result === 'failure') {
    const target = gameState.creatures.find(c => c.id === targetId);
    if (target) {
      const selectedWeapon = ctx.getSelectedWeapon(actor, weaponId);
      const baseFormula = selectedWeapon?.damageDice ?? actor.weaponDamageDice ?? '1d4';
      const dieMatch = baseFormula.match(/(\d+)d(\d+)/i);
      const numDice = dieMatch ? parseInt(dieMatch[1], 10) : 1;
      // Minimum damage = number of dice (each die = 1), no modifiers
      const minDamage = Math.max(1, numDice);

      const weaponDamageType: any = selectedWeapon?.damageType
        ?? actor.weaponDamageType ?? 'bludgeoning';
      const damageCalc = calculateFinalDamage(minDamage, weaponDamageType, target);
      target.currentHealth -= damageCalc.finalDamage;

      return {
        success: true,
        message: `ÃƒÂ¢Ã…â€œÃ¢â‚¬Â¦ Certain Strike! ${actor.name} misses but still deals ${damageCalc.finalDamage} minimum damage to ${target.name}!`,
        details: strikeResult.details
      };
    }
  }
  return strikeResult;
}

