/**
 * Triple Shot (Fighter 6, 2 actions, Flourish)
 * Three ranged Strikes at -2, each counts as 1 attack for MAP.
 */
export function resolveTripleShot(ctx: FeatActionContext, actor: Creature, gameState: GameState, weaponId?: string, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Triple Shot')) {
    return { success: false, message: `${actor.name} does not have Triple Shot.` , errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.flourishUsedThisTurn) {
    return { success: false, message: `${actor.name} has already used a Flourish action this turn.` , errorCode: 'FLOURISH_USED' };
  }
  actor.flourishUsedThisTurn = true;

  const messages: string[] = [];
  const savedMAP = actor.attacksMadeThisTurn;

  // Three strikes, all at original MAP with -2 penalty
  for (let i = 0; i < 3; i++) {
    actor.attacksMadeThisTurn = savedMAP; // Reset to same MAP for each shot
    // Apply -2 penalty temporarily via condition
    if (!actor.conditions) actor.conditions = [];
    actor.conditions.push({ name: 'triple-shot-penalty', duration: 0, value: 2, source: 'triple-shot' });
    const result = ctx.resolveAttackAction(actor, gameState, targetId, weaponId, { isVicious: false }, heroPointsSpent);
    actor.conditions = actor.conditions.filter(c => c.name !== 'triple-shot-penalty');
    if (result.success) {
      messages.push(`Shot ${i + 1}: ${result.details?.result ?? 'unknown'}`);
    }
  }
  // Triple Shot counts as 1 attack for MAP
  actor.attacksMadeThisTurn = savedMAP + 1;

  return {
    success: true,
    message: `ÃƒÂ°Ã…Â¸Ã‚ÂÃ‚Â¹ÃƒÂ°Ã…Â¸Ã‚ÂÃ‚Â¹ÃƒÂ°Ã…Â¸Ã‚ÂÃ‚Â¹ Triple Shot! ${actor.name} fires 3 arrows: ${messages.join('; ')}`,
  };
}

