/**
 * Spring from the Shadows (Rogue 12, 1 action, Flourish)
 * Strike from hidden/undetected; foe is off-guard.
 */
export function resolveSpringFromTheShadows(ctx: FeatActionContext, actor: Creature, gameState: GameState, weaponId?: string, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Spring from the Shadows')) {
    return { success: false, message: `${actor.name} does not have Spring from the Shadows.` , errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.flourishUsedThisTurn) {
    return { success: false, message: `${actor.name} has already used a Flourish action this turn.` , errorCode: 'FLOURISH_USED' };
  }
  actor.flourishUsedThisTurn = true;

  // Make target off-guard for this Strike
  const target = gameState.creatures.find(c => c.id === targetId);
  if (target) {
    if (!target.conditions) target.conditions = [];
    // Temporarily make off-guard
    target.conditions.push({ name: 'off-guard', duration: 0, value: 1, source: 'spring-from-shadows' });
  }

  const strikeResult = ctx.resolveAttackAction(actor, gameState, targetId, weaponId, { isVicious: false }, heroPointsSpent);
  strikeResult.message = `ÃƒÂ°Ã…Â¸Ã…â€™Ã¢â‚¬ËœÃƒÂ¢Ã…Â¡Ã¢â‚¬ÂÃƒÂ¯Ã‚Â¸Ã‚Â Spring from the Shadows! ${actor.name} leaps from hiding! ` + (strikeResult.message ?? '');

  // Remove the temporary off-guard
  if (target && target.conditions) {
    target.conditions = target.conditions.filter(c => c.source !== 'spring-from-shadows');
  }
  return strikeResult;
}

