/**
 * Incredible Ricochet (Fighter 12, 1 action, Concentrate, Press)
 * After thrown hit, additional Strike vs different target within 10ft.
 */
export function resolveIncredibleRicochet(ctx: FeatActionContext, actor: Creature, gameState: GameState, weaponId?: string, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Incredible Ricochet')) {
    return { success: false, message: `${actor.name} does not have Incredible Ricochet.` , errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  // Strike the primary target
  const strikeResult = ctx.resolveAttackAction(actor, gameState, targetId, weaponId, { isVicious: false }, heroPointsSpent);
  if (!strikeResult.success) return strikeResult;

  if (strikeResult.details?.result === 'success' || strikeResult.details?.result === 'critical-success') {
    const primaryTarget = gameState.creatures.find(c => c.id === targetId);
    if (primaryTarget) {
      // Find additional targets within 10ft (2 tiles) of primary
      const secondTargets = gameState.creatures.filter(c =>
        c.id !== actor.id && c.id !== targetId && c.currentHealth > 0 &&
        ctx.calculateDistance(primaryTarget.positions, c.positions) <= 2
      );
      if (secondTargets.length > 0) {
        const second = secondTargets[0];
        const secondResult = ctx.resolveAttackAction(actor, gameState, second.id, weaponId, { isVicious: false }, heroPointsSpent);
        if (secondResult.success) {
          strikeResult.message += ` ÃƒÂ°Ã…Â¸Ã‚ÂªÃ†â€™ÃƒÂ°Ã…Â¸Ã¢â‚¬â„¢Ã‚Â¥ Incredible Ricochet! Weapon bounces to ${second.name}: ${secondResult.message}`;
        }
      }
    }
  }
  return strikeResult;
}

