/** All stance condition names for mutual exclusion */
const ALL_STANCE_NAMES = [
  'disarming-stance', 'ricochet-stance', 'disruptive-stance',
  'lunging-stance', 'multishot-stance', 'point-blank-stance',
  'haft-striker-stance', 'dueling-dance', 'graceful-poise', 'twinned-defense',
];

/**
 * Lightning Swap (Fighter 2, 1 action, Flourish)
 * Interact to stow any number of items, then draw up to two weapons
 * or a shield and a weapon.
 */
export function resolveLightningSwap(ctx: FeatActionContext, actor: Creature, gameState?: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Lightning Swap')) {
    return { success: false, message: `${actor.name} does not have Lightning Swap.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.flourishUsedThisTurn) {
    return { success: false, message: `${actor.name} has already used a Flourish action this turn.`, errorCode: 'FLOURISH_USED' };
  }
  actor.flourishUsedThisTurn = true;

  // Stow all currently held items
  const heldWeapons = actor.weaponInventory?.filter(s => s.state === 'held') || [];
  for (const slot of heldWeapons) {
    slot.state = 'stowed';
  }
  const stowedCount = heldWeapons.length;

  // Draw up to two weapons (first two stowed weapons)
  const stowed = actor.weaponInventory?.filter(s => s.state === 'stowed') || [];
  const toDraw = stowed.slice(0, 2);
  for (const slot of toDraw) {
    slot.state = 'held';
  }
  const drawnNames = toDraw.map(s => s.weapon.display).join(' and ');

  return {
    success: true,
    message: `Lightning Swap: ${actor.name} stowed ${stowedCount} item(s), drew ${drawnNames || 'nothing'}.`,
  };
}

/**
 * Haft Striker Stance (Fighter 4, 1 action, Stance)
 * Requirements: Wielding a two-handed weapon in the hammer, spear, or polearm group.
 * Treat the haft as a simple melee weapon: 1d4 B, club group, agile+finesse.
 * Enables dual-wielding feats using haft as second weapon.
 */
export function resolveHaftStrikerStance(ctx: FeatActionContext, actor: Creature): ActionResult {
  if (!ctx.hasFeat(actor, 'Haft Striker Stance')) {
    return { success: false, message: `${actor.name} does not have Haft Striker Stance.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (!actor.conditions) actor.conditions = [];
  const existing = actor.conditions.findIndex(c => c.name === 'haft-striker-stance');
  if (existing >= 0) {
    actor.conditions.splice(existing, 1);
    return { success: true, message: `${actor.name} leaves Haft Striker Stance.` };
  }
  // Requirement: wielding a 2H weapon in hammer, spear, or polearm group
  const heldWeapons = actor.weaponInventory?.filter(s => s.state === 'held') || [];
  const valid2H = heldWeapons.find(s => {
    const traits = s.weapon.traits?.map(t => typeof t === 'string' ? t.toLowerCase() : '') || [];
    const catalogId = (s.weapon.weaponCatalogId || '').toLowerCase();
    const isTwoHand = traits.some(t => t.startsWith('two-hand')) || s.weapon.hands === 2;
    const isValidGroup = catalogId.includes('hammer') || catalogId.includes('spear') || catalogId.includes('polearm') || catalogId.includes('glaive') || catalogId.includes('halberd') || catalogId.includes('guisarme') || traits.includes('polearm') || traits.includes('spear') || traits.includes('hammer');
    return isTwoHand && isValidGroup;
  });
  if (!valid2H) {
    return { success: false, message: `${actor.name} must be wielding a two-handed hammer, spear, or polearm for Haft Striker Stance.`, errorCode: 'INVALID_WEAPON' };
  }
  // Remove other stances
  actor.conditions = actor.conditions.filter(c => !ALL_STANCE_NAMES.filter(n => n !== 'haft-striker-stance').includes(c.name));
  actor.conditions.push({ name: 'haft-striker-stance', duration: 'permanent', value: 1, source: 'haft-striker-stance' });
  return { success: true, message: `${actor.name} enters Haft Striker Stance! Weapon haft treated as agile/finesse 1d4 B club for dual-wielding.` };
}

/**
 * Slam Down (Fighter 4, 2 actions, Flourish)
 * Make a melee Strike. If it hits and deals damage, attempt an Athletics
 * check to Trip the target. Both count toward MAP but penalty doesn't
 * increase until after both attacks.
 */
export function resolveSlamDown(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, weaponId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Slam Down')) {
    return { success: false, message: `${actor.name} does not have Slam Down.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.flourishUsedThisTurn) {
    return { success: false, message: `${actor.name} has already used a Flourish action this turn.`, errorCode: 'FLOURISH_USED' };
  }
  actor.flourishUsedThisTurn = true;

  if (!targetId) {
    return { success: false, message: 'No target specified for Slam Down.', errorCode: 'NO_TARGET' };
  }

  // Remember current MAP
  const initialAttacks = actor.attacksMadeThisTurn ?? 0;

  // Perform the melee Strike
  const strikeResult = ctx.resolveAttackAction(actor, gameState, targetId, weaponId, { isVicious: false }, heroPointsSpent);
  if (!strikeResult.success) return strikeResult;

  // Reset MAP so Trip uses the same penalty as the Strike
  actor.attacksMadeThisTurn = initialAttacks;

  // If Strike hit and dealt damage, attempt free Trip
  const didHit = strikeResult.details?.result === 'success' || strikeResult.details?.result === 'critical-success';
  const dealtDamage = (strikeResult.details?.damage?.appliedDamage || 0) > 0;
  if (didHit && dealtDamage) {
    const tripResult = ctx.resolveTrip(actor, gameState, targetId, 0);
    if (tripResult.success) {
      strikeResult.message += ` Slam Down! ${tripResult.message}`;
    }
  }

  // Now advance MAP for both attacks
  actor.attacksMadeThisTurn = initialAttacks + 2;

  return strikeResult;
}

/**
 * Cut from the Air (Fighter 10, Reaction)
 * Trigger: You are the target of a physical ranged Strike.
 * Requirements: Aware of attack, not off-guard, have melee weapon or free hand.
 * You gain a +4 circumstance bonus to AC against the triggering attack.
 */
export function resolveCutFromTheAir(ctx: FeatActionContext, actor: Creature): ActionResult {
  if (!ctx.hasFeat(actor, 'Cut from the Air')) {
    return { success: false, message: `${actor.name} does not have Cut from the Air.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this turn.`, errorCode: 'REACTION_USED' };
  }
  // Check off-guard
  const isOffGuard = actor.conditions?.some(c => c.name === 'off-guard' || c.name === 'flat-footed');
  if (isOffGuard) {
    return { success: false, message: `${actor.name} is off-guard and cannot use Cut from the Air.`, errorCode: 'OFF_GUARD' };
  }
  // Check for melee weapon or free hand
  const heldWeapons = actor.weaponInventory?.filter(s => s.state === 'held') || [];
  const hasMeleeWeapon = heldWeapons.some(s => {
    const range = s.weapon.range ?? 5;
    return range <= 10; // melee weapons have range 5 or 10 (reach)
  });
  const handsUsed = actor.handsUsed ?? heldWeapons.length;
  const hasFreeHand = handsUsed < 2;
  if (!hasMeleeWeapon && !hasFreeHand) {
    return { success: false, message: `${actor.name} must have a melee weapon or free hand for Cut from the Air.`, errorCode: 'NO_VALID_WEAPON' };
  }

  actor.reactionUsed = true;

  // Apply +4 circumstance bonus to AC
  if (!actor.bonuses) actor.bonuses = [];
  actor.bonuses.push({ source: 'cut-from-the-air', value: 4, type: 'circumstance', applyTo: 'ac' });

  return {
    success: true,
    message: `REACTION: ${actor.name} cuts the projectile from the air! +4 circumstance bonus to AC against the triggering attack.`,
  };
}

/**
 * Mirror Shield (Fighter 10, Reaction)
 * Trigger: Opponent casting a spell that targets you critically fails a spell
 * attack roll against your AC.
 * Requirements: You have a shield raised.
 * Effect: Reflect the spell back against the caster.
 */
export function resolveMirrorShield(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Mirror Shield')) {
    return { success: false, message: `${actor.name} does not have Mirror Shield.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this turn.`, errorCode: 'REACTION_USED' };
  }
  if (!actor.shieldRaised) {
    return { success: false, message: `${actor.name} must have a shield raised for Mirror Shield.`, errorCode: 'SHIELD_NOT_RAISED' };
  }

  actor.reactionUsed = true;

  // The spell is reflected back to the caster
  const caster = targetId ? gameState.creatures.find(c => c.id === targetId) : null;
  if (!caster) {
    return {
      success: true,
      message: `REACTION: ${actor.name} reflects the spell back with Mirror Shield! The spell is redirected at the caster.`,
    };
  }

  return {
    success: true,
    message: `REACTION: ${actor.name} reflects the spell back at ${caster.name} with Mirror Shield! The caster suffers the effects of their own spell.`,
    details: { reflectedTo: caster.id },
  };
}

/**
 * Twin Riposte (Fighter 10, Reaction)
 * Trigger: A creature within your reach critically fails a Strike against you.
 * Requirements: You are benefiting from Twin Parry.
 * Effect: Make a melee Strike or attempt to Disarm the triggering opponent.
 */
export function resolveTwinRiposte(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, weaponId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Twin Riposte')) {
    return { success: false, message: `${actor.name} does not have Twin Riposte.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this turn.`, errorCode: 'REACTION_USED' };
  }
  // Check for Twin Parry benefit (bonus or twinned-defense stance)
  const hasTwinParryBenefit = actor.bonuses?.some(b => b.source === 'twin-parry') ||
    actor.conditions?.some(c => c.name === 'twinned-defense');
  // Improved Twin Riposte relaxes the requirement
  const hasImproved = ctx.hasFeat(actor, 'Improved Twin Riposte');
  if (!hasTwinParryBenefit && !hasImproved) {
    const heldWeapons = actor.weaponInventory?.filter(s => s.state === 'held') || [];
    if (!hasImproved || heldWeapons.length < 2) {
      return { success: false, message: `${actor.name} must be benefiting from Twin Parry to use Twin Riposte.`, errorCode: 'MISSING_PREREQUISITE' };
    }
  }
  if (!targetId) {
    return { success: false, message: 'No target specified for Twin Riposte.', errorCode: 'NO_TARGET' };
  }

  actor.reactionUsed = true;

  // Make a melee Strike against the triggering creature
  const strikeResult = ctx.resolveAttackAction(actor, gameState, targetId, weaponId, { isVicious: false }, heroPointsSpent);
  if (strikeResult.success) {
    strikeResult.message = `REACTION: Twin Riposte! ${strikeResult.message}`;
  }
  return strikeResult;
}

/**
 * Dueling Dance (Fighter 12, 1 action, Stance)
 * Requirements: Wielding only a single one-handed melee weapon, other hand free.
 * While in stance, you constantly benefit from Dueling Parry (+2 circ to AC).
 */
export function resolveDuelingDance(ctx: FeatActionContext, actor: Creature): ActionResult {
  if (!ctx.hasFeat(actor, 'Dueling Dance')) {
    return { success: false, message: `${actor.name} does not have Dueling Dance.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (!actor.conditions) actor.conditions = [];
  const existing = actor.conditions.findIndex(c => c.name === 'dueling-dance');
  if (existing >= 0) {
    actor.conditions.splice(existing, 1);
    // Remove the persistent AC bonus
    if (actor.bonuses) {
      actor.bonuses = actor.bonuses.filter(b => b.source !== 'dueling-dance');
    }
    return { success: true, message: `${actor.name} leaves Dueling Dance.` };
  }
  // Requirements: single 1H melee weapon, other hand free
  const heldWeapons = actor.weaponInventory?.filter(s => s.state === 'held') || [];
  if (heldWeapons.length !== 1) {
    return { success: false, message: `${actor.name} must be wielding exactly one weapon with the other hand free for Dueling Dance.`, errorCode: 'INVALID_WEAPON' };
  }
  // Remove other stances
  actor.conditions = actor.conditions.filter(c => !ALL_STANCE_NAMES.filter(n => n !== 'dueling-dance').includes(c.name));
  actor.conditions.push({ name: 'dueling-dance', duration: 'permanent', value: 1, source: 'dueling-dance' });
  // Apply persistent Dueling Parry bonus
  if (!actor.bonuses) actor.bonuses = [];
  actor.bonuses.push({ source: 'dueling-dance', value: 2, type: 'circumstance', applyTo: 'ac' });
  return { success: true, message: `${actor.name} enters Dueling Dance! Persistent +2 circumstance bonus to AC (Dueling Parry).` };
}

/**
 * Opening Stance (Fighter 14, Free Action)
 * Trigger: You roll initiative.
 * Effect: You can immediately use an action that has the stance trait as a free action.
 */
export function resolveOpeningStance(ctx: FeatActionContext, actor: Creature, gameState?: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Opening Stance')) {
    return { success: false, message: `${actor.name} does not have Opening Stance.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  // Mark that the actor can use a free stance action
  if (!actor.conditions) actor.conditions = [];
  actor.conditions.push({ name: 'opening-stance-ready', duration: 1, value: 1, source: 'opening-stance' });
  return {
    success: true,
    message: `${actor.name} uses Opening Stance! They may immediately enter a stance as a free action. Choose a stance to activate.`,
  };
}

/**
 * Graceful Poise (Fighter 16, 1 action, Stance)
 * Requirements: Wielding two melee weapons, one in each hand.
 * While in stance, when making second Strike from Double Slice,
 * MAP is -3 with agile (-4 normally) or -4 without agile (-5 normally).
 */
export function resolveGracefulPoise(ctx: FeatActionContext, actor: Creature): ActionResult {
  if (!ctx.hasFeat(actor, 'Graceful Poise')) {
    return { success: false, message: `${actor.name} does not have Graceful Poise.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (!actor.conditions) actor.conditions = [];
  const existing = actor.conditions.findIndex(c => c.name === 'graceful-poise');
  if (existing >= 0) {
    actor.conditions.splice(existing, 1);
    return { success: true, message: `${actor.name} leaves Graceful Poise.` };
  }
  // Requirements: two melee weapons
  const heldWeapons = actor.weaponInventory?.filter(s => s.state === 'held') || [];
  if (heldWeapons.length < 2) {
    return { success: false, message: `${actor.name} must be wielding two melee weapons for Graceful Poise.`, errorCode: 'INSUFFICIENT_WEAPONS' };
  }
  // Remove other stances
  actor.conditions = actor.conditions.filter(c => !ALL_STANCE_NAMES.filter(n => n !== 'graceful-poise').includes(c.name));
  actor.conditions.push({ name: 'graceful-poise', duration: 'permanent', value: 1, source: 'graceful-poise' });
  return { success: true, message: `${actor.name} enters Graceful Poise! Double Slice second Strike MAP reduced by 1.` };
}

/**
 * Needle in the God's Eyes (Fighter 16, 2 actions)
 * Leap up to your total Speed horizontally or vertically, then Strike
 * twice at any point during the Leap. Both attacks count toward MAP
 * but penalty doesn't increase until both attacks are made.
 */
export function resolveNeedleInTheGodsEyes(ctx: FeatActionContext, actor: Creature, gameState: GameState, weaponId?: string, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, "Needle in the God's Eyes")) {
    return { success: false, message: `${actor.name} does not have Needle in the God's Eyes.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (!targetId) {
    return { success: false, message: "No target specified for Needle in the God's Eyes.", errorCode: 'NO_TARGET' };
  }

  // Remember current MAP
  const initialAttacks = actor.attacksMadeThisTurn ?? 0;

  // Perform Leap (represented as movement up to full Speed)
  const speed = getEffectiveSpeed(actor);
  const messages: string[] = [`${actor.name} makes a tremendous leap (up to ${speed}ft)!`];

  // First Strike
  const strike1 = ctx.resolveAttackAction(actor, gameState, targetId, weaponId, { isVicious: false }, heroPointsSpent);
  if (!strike1.success) return strike1;

  // Reset MAP for second strike (same penalty)
  actor.attacksMadeThisTurn = initialAttacks;

  // Second Strike
  const strike2 = ctx.resolveAttackAction(actor, gameState, targetId, weaponId, { isVicious: false }, heroPointsSpent);

  // Advance MAP for both attacks
  actor.attacksMadeThisTurn = initialAttacks + 2;

  const totalDamage = (strike1.details?.damage?.appliedDamage || 0) + (strike2.details?.damage?.appliedDamage || 0);
  messages.push(strike1.message);
  if (strike2.success) messages.push(strike2.message);

  return {
    success: true,
    message: messages.join(' '),
    details: { strike1: strike1.details, strike2: strike2?.details },
    totalDamage,
  };
}

/**
 * Twinned Defense (Fighter 16, 1 action, Stance)
 * Requirements: Wielding two melee weapons, one in each hand.
 * While in stance, you constantly gain Twin Parry benefits:
 * +1 circumstance to AC (+2 if either weapon has parry trait).
 */
export function resolveTwinnedDefense(ctx: FeatActionContext, actor: Creature): ActionResult {
  if (!ctx.hasFeat(actor, 'Twinned Defense')) {
    return { success: false, message: `${actor.name} does not have Twinned Defense.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (!actor.conditions) actor.conditions = [];
  const existing = actor.conditions.findIndex(c => c.name === 'twinned-defense');
  if (existing >= 0) {
    actor.conditions.splice(existing, 1);
    // Remove the persistent AC bonus
    if (actor.bonuses) {
      actor.bonuses = actor.bonuses.filter(b => b.source !== 'twinned-defense');
    }
    return { success: true, message: `${actor.name} leaves Twinned Defense.` };
  }
  // Requirements: two melee weapons
  const heldWeapons = actor.weaponInventory?.filter(s => s.state === 'held') || [];
  if (heldWeapons.length < 2) {
    return { success: false, message: `${actor.name} must be wielding two melee weapons for Twinned Defense.`, errorCode: 'INSUFFICIENT_WEAPONS' };
  }
  // Check for parry trait
  let acBonus = 1;
  const hasParryTrait = heldWeapons.some(s =>
    s.weapon.traits?.some(t => typeof t === 'string' && t.toLowerCase() === 'parry')
  );
  if (hasParryTrait) acBonus = 2;
  // Remove other stances
  actor.conditions = actor.conditions.filter(c => !ALL_STANCE_NAMES.filter(n => n !== 'twinned-defense').includes(c.name));
  actor.conditions.push({ name: 'twinned-defense', duration: 'permanent', value: 1, source: 'twinned-defense' });
  // Apply persistent Twin Parry bonus
  if (!actor.bonuses) actor.bonuses = [];
  actor.bonuses.push({ source: 'twinned-defense', value: acBonus, type: 'circumstance', applyTo: 'ac' });
  return { success: true, message: `${actor.name} enters Twinned Defense! Persistent +${acBonus} circumstance bonus to AC (Twin Parry).` };
}

