/**
 * Counter Thought (Psychic 1, Reaction)
 * Trigger: A creature Casts a Spell with the mental trait.
 * Expend a spell slot to counteract the triggering mental spell.
 */
export function resolveCounterThought(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Counter Thought')) {
    return { success: false, message: `${actor.name} does not have Counter Thought.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }

  // Check for an available spell slot (simplified: check if any slots remain)
  const spellSlots = (actor as any).spellSlots ?? [];
  const availableSlot = spellSlots.find((s) => s.remaining > 0);
  if (!availableSlot) {
    return { success: false, message: `${actor.name} has no spell slots remaining to power Counter Thought.`, errorCode: 'NO_SPELL_SLOTS' };
  }

  actor.reactionUsed = true;
  availableSlot.remaining -= 1;

  // Counteract check: d20 + level + key ability vs DC (target level-based)
  const roll = rollD20();
  const counteractMod = actor.level + ((actor.abilities as any)?.intelligence ?? (actor.abilities as any)?.charisma ?? 0);
  const total = roll + counteractMod;
  const counteractDC = 15 + (availableSlot.rank ?? 1) * 2; // approximate DC based on spell rank
  const success = total >= counteractDC;

  return {
    success: true,
    message: success
      ? `🧠✋ Counter Thought! ${actor.name} expends a rank ${availableSlot.rank ?? 1} spell slot and rolls ${roll}+${counteractMod}=${total} vs DC ${counteractDC}: Success! The mental spell is counteracted!`
      : `🧠✋ Counter Thought! ${actor.name} expends a rank ${availableSlot.rank ?? 1} spell slot and rolls ${roll}+${counteractMod}=${total} vs DC ${counteractDC}: Failed to counteract the spell.`,
  };
}

/**
 * Irezoko Tattoo (Psychic 4, Free Action)
 * Once per day: amp a psi cantrip without spending a Focus Point.
 * Can't use while Psyche is Unleashed.
 */
export function resolveIrezokoTattoo(ctx: FeatActionContext, actor: Creature, gameState?: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Irezoko Tattoo')) {
    return { success: false, message: `${actor.name} does not have Irezoko Tattoo.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  const cooldown = actor.conditions?.find(c => c.name === 'irezoko-tattoo-used');
  if (cooldown) {
    return { success: false, message: `${actor.name} has already used Irezoko Tattoo today.`, errorCode: 'ALREADY_USED' };
  }
  const psycheUnleashed = actor.conditions?.find(c => c.name === 'unleash-psyche');
  if (psycheUnleashed) {
    return { success: false, message: `${actor.name} cannot use Irezoko Tattoo while Psyche is Unleashed.`, errorCode: 'VALIDATION_FAILED' };
  }

  if (!actor.conditions) actor.conditions = [];
  actor.conditions.push({ name: 'irezoko-tattoo-used', duration: 'permanent', value: 1, source: 'irezoko-tattoo' });
  actor.conditions.push({ name: 'irezoko-tattoo-amp', duration: 1, value: 1, source: 'irezoko-tattoo' });

  return {
    success: true,
    message: `🎨🧠 ${actor.name} activates their Irezoko Tattoo! Next psi cantrip amp is free (no Focus Point cost).`,
  };
}

/**
 * Mental Static (Psychic 8, Reaction)
 * Trigger: An ally within 30 feet is hit or critically hit by an attack.
 * Treat ally's AC as +2 vs triggering attack. If this changes hit→miss, can't use again for 1d4 rounds.
 */
export function resolveMentalStatic(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Mental Static')) {
    return { success: false, message: `${actor.name} does not have Mental Static.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }
  const cooldown = actor.conditions?.find(c => c.name === 'mental-static-cooldown');
  if (cooldown) {
    return { success: false, message: `${actor.name} cannot use Mental Static yet (cooldown active).`, errorCode: 'ALREADY_USED' };
  }
  if (!targetId) return { success: false, message: 'No ally specified for Mental Static.', errorCode: 'NO_TARGET' };
  const ally = gameState.creatures.find(c => c.id === targetId);
  if (!ally) return { success: false, message: 'Ally not found.', errorCode: 'TARGET_NOT_FOUND' };

  const dist = ctx.calculateDistance(actor.positions, ally.positions);
  if (dist > 6) { // 30 feet = 6 squares
    return { success: false, message: `${ally.name} is too far away for Mental Static (max 30ft).`, errorCode: 'OUT_OF_RANGE' };
  }

  actor.reactionUsed = true;

  // Apply +2 AC condition to the ally temporarily
  if (!ally.conditions) ally.conditions = [];
  ally.conditions.push({ name: 'mental-static', duration: 0, value: 2, source: 'mental-static' });
  if (!ally.bonuses) ally.bonuses = [];
  ally.bonuses.push({ source: 'mental-static', value: 2, type: 'circumstance', applyTo: 'ac' });

  // Check if the AC boost would convert hit→miss (simplified: apply cooldown if effective)
  const cooldownRounds = Math.floor(Math.random() * 4) + 1; // 1d4
  if (!actor.conditions) actor.conditions = [];
  actor.conditions.push({ name: 'mental-static-cooldown', duration: cooldownRounds, value: 1, source: 'mental-static' });

  return {
    success: true,
    message: `🧠🛡️ Mental Static! ${actor.name} disrupts the attack against ${ally.name}! (+2 circumstance AC vs triggering attack). Cooldown: ${cooldownRounds} rounds.`,
  };
}

/**
 * Foreseen Failure (Psychic 12, Reaction)
 * Trigger: A creature within 30 feet that you can observe Casts a Spell.
 * Counteract triggering spell with +2 circumstance bonus. Fortune trait.
 */
export function resolveForeseenFailure(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Foreseen Failure')) {
    return { success: false, message: `${actor.name} does not have Foreseen Failure.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }

  actor.reactionUsed = true;

  // Counteract with +2 bonus (Fortune: roll twice, take best)
  const roll1 = rollD20();
  const roll2 = rollD20();
  const bestRoll = Math.max(roll1, roll2);
  const counteractMod = actor.level + ((actor.abilities as any)?.intelligence ?? (actor.abilities as any)?.charisma ?? 0) + 2; // +2 circumstance
  const total = bestRoll + counteractMod;
  const counteractDC = 15 + actor.level; // approximate spell DC
  const success = total >= counteractDC;

  return {
    success: true,
    message: success
      ? `🔮✨ Foreseen Failure! ${actor.name} glimpses the future! Rolls ${roll1} & ${roll2} (Fortune, best: ${bestRoll})+${counteractMod}=${total} vs DC ${counteractDC}: The spell is counteracted!`
      : `🔮 Foreseen Failure! ${actor.name} rolls ${roll1} & ${roll2} (Fortune, best: ${bestRoll})+${counteractMod}=${total} vs DC ${counteractDC}: Failed to counteract the spell.`,
  };
}

/**
 * No!!! (Psychic 12, Reaction)
 * Trigger: An ally within 30 feet is hit by an attack.
 * Ally gains resistance to all damage vs triggering attack = 2 + level (4 + level at 18th).
 */
export function resolveNo(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'No!!!')) {
    return { success: false, message: `${actor.name} does not have No!!!`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }
  if (!targetId) return { success: false, message: 'No ally specified for No!!!', errorCode: 'NO_TARGET' };
  const ally = gameState.creatures.find(c => c.id === targetId);
  if (!ally) return { success: false, message: 'Ally not found.', errorCode: 'TARGET_NOT_FOUND' };

  const dist = ctx.calculateDistance(actor.positions, ally.positions);
  if (dist > 6) { // 30 feet
    return { success: false, message: `${ally.name} is too far away for No!!! (max 30ft).`, errorCode: 'OUT_OF_RANGE' };
  }

  actor.reactionUsed = true;

  const resistanceValue = actor.level >= 18 ? 4 + actor.level : 2 + actor.level;
  if (!ally.conditions) ally.conditions = [];
  ally.conditions.push({ name: 'no-resistance', duration: 0, value: resistanceValue, source: 'no!!!' });

  return {
    success: true,
    message: `🧠💥 NO!!! ${actor.name} psychically screams to protect ${ally.name}! Resistance ${resistanceValue} to all damage against the triggering attack!`,
  };
}

