/**
 * Scout's Warning (Rogue/Ranger 4, Free Action)
 * Trigger: You are about to roll initiative.
 * Allies each get +1 circumstance bonus to initiative (+2 if Scout activity).
 */
export function resolveScoutsWarning(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!ctx.hasFeat(actor, "Scout's Warning")) {
    return { success: false, message: `${actor.name} does not have Scout's Warning.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }

  const isScouting = actor.conditions?.some(c => c.name === 'scouting') ?? false;
  const bonus = isScouting ? 2 : 1;

  // Apply initiative bonus to all allies
  const allies = gameState.creatures.filter(c =>
    c.id !== actor.id && c.currentHealth > 0 &&
    c.type === 'player'
  );

  for (const ally of allies) {
    if (!ally.bonuses) ally.bonuses = [];
    ally.bonuses.push({ source: 'scouts-warning', value: bonus, type: 'circumstance', applyTo: 'initiative' });
  }

  return {
    success: true,
    message: `⚠️👁️ Scout's Warning! ${actor.name} warns allies of danger! All allies gain +${bonus} circumstance bonus to initiative${isScouting ? ' (Scout activity)' : ''}.`,
  };
}

/**
 * Shove Down (Rogue 6, Free Action)
 * Requirements: Your last action was a successful Shove.
 * Attempt to Trip the target even if no longer in reach.
 */
export function resolveShoveDown(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Shove Down')) {
    return { success: false, message: `${actor.name} does not have Shove Down.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (!targetId) return { success: false, message: 'No target specified for Shove Down.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };

  // Attempt Trip (ignoring reach requirement per feat text)
  const tripResult = ctx.resolveTrip(actor, gameState, targetId, heroPointsSpent);

  return {
    success: true,
    message: `🦵💨 Shove Down! ${actor.name} follows up the Shove with a Trip!\n${tripResult.message}`,
    details: tripResult.details,
  };
}

/**
 * Delay Trap (Rogue 8, Reaction)
 * Trigger: A trap within your reach is triggered.
 * Thievery check to delay/prevent the trap.
 */
export function resolveDelayTrap(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Delay Trap')) {
    return { success: false, message: `${actor.name} does not have Delay Trap.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }

  actor.reactionUsed = true;

  const thievery = ctx.getSkillBonus(actor, 'thievery');
  const roll = rollD20();
  const total = roll + thievery;
  const dc = 10 + actor.level + 5; // approximate trap DC
  const degree = getDegreeOfSuccess(roll, total, dc);

  if (degree === 'critical-success') {
    return {
      success: true,
      message: `🔧✨ Delay Trap! ${actor.name} rolls ${roll}+${thievery}=${total} vs DC ${dc}: Critical Success! The trap is completely prevented from triggering!`,
    };
  } else if (degree === 'success') {
    return {
      success: true,
      message: `🔧 Delay Trap! ${actor.name} rolls ${roll}+${thievery}=${total} vs DC ${dc}: Success! The trap's activation is delayed until the start of next turn.`,
    };
  } else if (degree === 'critical-failure') {
    if (!actor.conditions) actor.conditions = [];
    actor.conditions.push({ name: 'off-guard', duration: 1, value: 1, source: 'delay-trap-crit-fail' });
    return {
      success: true,
      message: `🔧❌ Delay Trap! ${actor.name} rolls ${roll}+${thievery}=${total} vs DC ${dc}: Critical Failure! ${actor.name} is off-guard until start of next turn.`,
    };
  }
  return {
    success: true,
    message: `🔧 Delay Trap! ${actor.name} rolls ${roll}+${thievery}=${total} vs DC ${dc}: Failed to delay the trap.`,
  };
}

/**
 * Tactical Entry (Rogue 8, Free Action)
 * Requirements: You rolled Stealth for initiative, neither side has acted yet.
 * You Stride without triggering reactions.
 */
export function resolveTacticalEntry(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Tactical Entry')) {
    return { success: false, message: `${actor.name} does not have Tactical Entry.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }

  // Grant a free Stride that doesn't trigger reactions
  const speed = getEffectiveSpeed(actor);
  if (!actor.conditions) actor.conditions = [];
  actor.conditions.push({ name: 'tactical-entry', duration: 0, value: 1, source: 'tactical-entry' });

  return {
    success: true,
    message: `🥷 Tactical Entry! ${actor.name} Strides up to ${speed}ft without triggering any reactions!`,
  };
}

/**
 * Sense the Unseen (Rogue/Ranger/Investigator 14, Reaction)
 * Trigger: You fail a check to Seek.
 * Automatically sense undetected creatures, making them hidden instead.
 */
export function resolveSenseTheUnseen(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Sense the Unseen')) {
    return { success: false, message: `${actor.name} does not have Sense the Unseen.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }

  actor.reactionUsed = true;

  // Find undetected enemies within Seek range (30ft) and make them hidden
  const enemies = gameState.creatures.filter((c: Creature) =>
    c.currentHealth > 0 && c.type !== 'player' &&
    ctx.calculateDistance(actor.positions, c.positions) <= 6 &&
    c.conditions?.some((cond) => cond.name === 'undetected')
  );

  let revealed = 0;
  for (const enemy of enemies) {
    if (!enemy.conditions) continue;
    const idx = enemy.conditions.findIndex((c) => c.name === 'undetected');
    if (idx >= 0) {
      enemy.conditions.splice(idx, 1);
      enemy.conditions.push({ name: 'hidden', duration: 1, value: 1, source: 'sense-the-unseen' });
      revealed++;
    }
  }

  return {
    success: true,
    message: revealed > 0
      ? `👁️✨ Sense the Unseen! ${actor.name} instinctively detects ${revealed} hidden presence${revealed > 1 ? 's' : ''}! They are now merely hidden.`
      : `👁️ Sense the Unseen! ${actor.name} reaches out with their senses, but no undetected creatures are nearby.`,
  };
}

/**
 * Stay Down! (Rogue 14, Reaction)
 * Trigger: A prone foe within your reach Stands.
 * Athletics check vs foe's Fortitude DC. Success: disrupts Stand, foe stays prone.
 */
export function resolveStayDown(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Stay Down!')) {
    return { success: false, message: `${actor.name} does not have Stay Down!`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }
  if (!targetId) return { success: false, message: 'No target specified for Stay Down!', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };

  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 1.5) {
    return { success: false, message: `${target.name} is not within reach for Stay Down!`, errorCode: 'OUT_OF_RANGE' };
  }

  actor.reactionUsed = true;

  const athletics = ctx.getSkillBonus(actor, 'athletics');
  const roll = rollD20();
  const total = roll + athletics;
  const fortDC = ctx.getFortitudeDC(target);
  const degree = getDegreeOfSuccess(roll, total, fortDC);

  if (!target.conditions) target.conditions = [];
  if (degree === 'critical-success') {
    target.conditions.push({ name: 'prone', duration: 2, value: 1, source: 'stay-down' });
    return {
      success: true,
      message: `🦵💥 Stay Down! ${actor.name} rolls ${roll}+${athletics}=${total} vs Fort DC ${fortDC}: Critical! ${target.name} stays prone and can't Stand until next turn!`,
    };
  } else if (degree === 'success') {
    target.conditions.push({ name: 'prone', duration: 1, value: 1, source: 'stay-down' });
    return {
      success: true,
      message: `🦵 Stay Down! ${actor.name} rolls ${roll}+${athletics}=${total} vs Fort DC ${fortDC}: ${target.name}'s Stand is disrupted — still prone!`,
    };
  }
  return {
    success: true,
    message: `🦵 Stay Down! ${actor.name} rolls ${roll}+${athletics}=${total} vs Fort DC ${fortDC}: Failed — ${target.name} manages to stand up.`,
  };
}

/**
 * Swift Elusion (Rogue 16, Reaction)
 * Trigger: A foe ends its movement adjacent to you.
 * Acrobatics check vs foe's Reflex DC. Success: reposition.
 */
export function resolveSwiftElusion(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Swift Elusion')) {
    return { success: false, message: `${actor.name} does not have Swift Elusion.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }
  if (!targetId) return { success: false, message: 'No target specified for Swift Elusion.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };

  actor.reactionUsed = true;

  const acrobatics = ctx.getSkillBonus(actor, 'acrobatics');
  const roll = rollD20();
  const total = roll + acrobatics;
  const reflexDC = ctx.getReflexDC(target);
  const degree = getDegreeOfSuccess(roll, total, reflexDC);

  if (degree === 'success' || degree === 'critical-success') {
    // Move actor to a different space adjacent to the foe (simplified: Step)
    ctx.resolveStep(actor, gameState, null);
    return {
      success: true,
      message: `🏃💨 Swift Elusion! ${actor.name} rolls ${roll}+${acrobatics}=${total} vs Reflex DC ${reflexDC}: Success! ${actor.name} nimbly repositions!`,
    };
  }
  return {
    success: true,
    message: `🏃 Swift Elusion! ${actor.name} rolls ${roll}+${acrobatics}=${total} vs Reflex DC ${reflexDC}: Failed to reposition.`,
  };
}

/**
 * Hidden Paragon (Rogue 20, Reaction)
 * Trigger: You successfully Hide/Sneak and become hidden/undetected from all foes.
 * Become invisible for 1 minute (persists through hostile actions). Once per hour.
 */
export function resolveHiddenParagon(ctx: FeatActionContext, actor: Creature): ActionResult {
  if (!ctx.hasFeat(actor, 'Hidden Paragon')) {
    return { success: false, message: `${actor.name} does not have Hidden Paragon.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }
  const cooldown = actor.conditions?.find(c => c.name === 'hidden-paragon-used');
  if (cooldown) {
    return { success: false, message: `${actor.name} has already used Hidden Paragon this hour.`, errorCode: 'ALREADY_USED' };
  }

  actor.reactionUsed = true;
  if (!actor.conditions) actor.conditions = [];
  // Invisible for 1 minute (10 rounds)
  actor.conditions.push({ name: 'invisible', duration: 10, value: 1, source: 'hidden-paragon' });
  // Cooldown (effectively permanent for the encounter)
  actor.conditions.push({ name: 'hidden-paragon-used', duration: 'permanent', value: 1, source: 'hidden-paragon' });

  return {
    success: true,
    message: `👻✨ Hidden Paragon! ${actor.name} vanishes completely! Invisible for 1 minute — even hostile actions don't break it!`,
  };
}

/**
 * Reactive Distraction (Rogue 20, Reaction)
 * Trigger: You would be hit by an attack or targeted by an effect.
 * Use Perfect Distraction: decoy takes the attack instead.
 */
export function resolveReactiveDistraction(ctx: FeatActionContext, actor: Creature): ActionResult {
  if (!ctx.hasFeat(actor, 'Reactive Distraction')) {
    return { success: false, message: `${actor.name} does not have Reactive Distraction.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }

  actor.reactionUsed = true;
  if (!actor.conditions) actor.conditions = [];
  // Mark that the decoy absorbs the attack
  actor.conditions.push({ name: 'reactive-distraction', duration: 0, value: 1, source: 'reactive-distraction' });
  // Also become hidden (as per Perfect Distraction)
  actor.conditions.push({ name: 'hidden', duration: 1, value: 1, source: 'reactive-distraction' });

  return {
    success: true,
    message: `🎭💨 Reactive Distraction! ${actor.name} swaps with a decoy! The attack targets the decoy instead!`,
  };
}

