/**
 * Distant Waterbird's Poise (Magus 4, Reaction)
 * Trigger: You hit with a Spellstrike.
 * Leap/High Jump/Long Jump without triggering reactions. No initial Stride needed.
 * Walk on water/liquids until end of next turn.
 */
export function resolveDistantWaterbirdsPoise(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetPosition?: Position): ActionResult {
  if (!ctx.hasFeat(actor, "Distant Waterbird's Poise")) {
    return { success: false, message: `${actor.name} does not have Distant Waterbird's Poise.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }

  actor.reactionUsed = true;

  // Execute a Leap (up to full Speed without triggering reactions)
  const speed = getEffectiveSpeed(actor);
  if (targetPosition) {
    const dist = ctx.calculateDistance(actor.positions, targetPosition);
    if (dist <= speed / 5) {
      actor.positions = { x: targetPosition.x, y: targetPosition.y };
    }
  }

  if (!actor.conditions) actor.conditions = [];
  actor.conditions.push({ name: 'waterbird-poise', duration: 2, value: 1, source: 'distant-waterbirds-poise' });

  return {
    success: true,
    message: `🦅💧 Distant Waterbird's Poise! ${actor.name} leaps away gracefully after the Spellstrike! Can walk on water until end of next turn.`,
  };
}

/**
 * Emergency Targe (Magus 4, Reaction)
 * Trigger: Enemy hits with melee Strike/spell attack, or you fail a save vs spell.
 * Immediately Raise Shield or cast shield. Bonus applies retroactively.
 */
export function resolveEmergencyTarge(ctx: FeatActionContext, actor: Creature): ActionResult {
  if (!ctx.hasFeat(actor, 'Emergency Targe')) {
    return { success: false, message: `${actor.name} does not have Emergency Targe.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }

  actor.reactionUsed = true;

  // Apply shield bonus retroactively
  const shieldBonus = 2; // standard shield or shield spell
  if (!actor.conditions) actor.conditions = [];
  actor.conditions.push({ name: 'shield-raised', duration: 1, value: shieldBonus, source: 'emergency-targe' });
  if (!actor.bonuses) actor.bonuses = [];
  actor.bonuses.push({ source: 'emergency-targe', value: shieldBonus, type: 'circumstance', applyTo: 'ac' });

  return {
    success: true,
    message: `🛡️⚡ Emergency Targe! ${actor.name} reactively raises their shield! +${shieldBonus} circumstance bonus to AC applies to the triggering attack.`,
  };
}

/**
 * Reactive Strike (Magus 6, Reaction — same as Fighter AoO)
 * Trigger: Creature within reach uses manipulate/move action, ranged attack, or leaves square.
 * Make a melee Strike. Disrupt manipulate on crit.
 */
export function resolveMagusReactiveStrike(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, weaponId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Reactive Strike')) {
    return { success: false, message: `${actor.name} does not have Reactive Strike.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }
  if (!targetId) return { success: false, message: 'No target specified for Reactive Strike.', errorCode: 'NO_TARGET' };

  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };

  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 1.5) {
    return { success: false, message: `${target.name} is not within melee reach for Reactive Strike.`, errorCode: 'OUT_OF_RANGE' };
  }

  actor.reactionUsed = true;

  const strikeResult = ctx.resolveAttackAction(actor, gameState, targetId, weaponId, { isVicious: false }, heroPointsSpent);

  const disrupted = strikeResult.details?.result === 'critical-success' ? ' The manipulate action is disrupted!' : '';

  return {
    success: true,
    message: `⚔️ Reactive Strike! ${actor.name} lashes out!${disrupted}\n${strikeResult.message}`,
    details: strikeResult.details,
  };
}

/**
 * Capture Magic (Magus 8, Reaction)
 * Trigger: Succeed at save vs harmful spell, or foe fails spell attack vs you.
 * Enter Arcane Cascade (with spell's damage type) or +2 status to Arcane Cascade damage until end of next turn.
 */
export function resolveCaptureMagic(ctx: FeatActionContext, actor: Creature): ActionResult {
  if (!ctx.hasFeat(actor, 'Capture Magic')) {
    return { success: false, message: `${actor.name} does not have Capture Magic.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }

  actor.reactionUsed = true;

  const inCascade = actor.conditions?.some(c => c.name === 'arcane-cascade');
  if (!actor.conditions) actor.conditions = [];
  if (!actor.bonuses) actor.bonuses = [];

  if (inCascade) {
    // Boost existing Arcane Cascade
    actor.bonuses.push({ source: 'capture-magic', value: 2, type: 'status', applyTo: 'arcane-cascade-damage' });
    actor.conditions.push({ name: 'capture-magic-boost', duration: 2, value: 2, source: 'capture-magic' });
    return {
      success: true,
      message: `✨🔮 Capture Magic! ${actor.name} captures residual spell energy! +2 status bonus to Arcane Cascade damage until end of next turn.`,
    };
  } else {
    // Enter Arcane Cascade
    actor.conditions.push({ name: 'arcane-cascade', duration: 'permanent', value: 1, source: 'capture-magic' });
    actor.bonuses.push({ source: 'arcane-cascade', value: 1, type: 'status', applyTo: 'melee-damage' });
    return {
      success: true,
      message: `✨🔮 Capture Magic! ${actor.name} captures the spell's energy and enters Arcane Cascade!`,
    };
  }
}

/**
 * Crosscurrent Counter (Magus 8, Reaction)
 * Trigger: You become grabbed or restrained.
 * Grapple ignoring reach/free hand. Success: remove grab/restrain + pull adjacent.
 */
export function resolveCrosscurrentCounter(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Crosscurrent Counter')) {
    return { success: false, message: `${actor.name} does not have Crosscurrent Counter.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }
  if (!targetId) return { success: false, message: 'No target specified for Crosscurrent Counter.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };

  actor.reactionUsed = true;

  // Athletics check to Grapple (ignoring reach and free hand requirements)
  const athletics = ctx.getSkillBonus(actor, 'athletics');
  const roll = rollD20();
  const total = roll + athletics;
  const fortDC = ctx.getFortitudeDC(target);
  const degree = getDegreeOfSuccess(roll, total, fortDC);

  if (degree === 'critical-success' || degree === 'success') {
    // Remove grabbed/restrained from actor
    if (actor.conditions) {
      actor.conditions = actor.conditions.filter(c => !['grabbed', 'restrained'].includes(c.name));
    }
    // Pull target adjacent
    const dx = actor.positions.x - target.positions.x;
    const dy = actor.positions.y - target.positions.y;
    const dist = Math.sqrt(dx * dx + dy * dy);
    if (dist > 1.5) {
      const normX = dx / dist;
      const normY = dy / dist;
      target.positions.x = Math.round(actor.positions.x - normX);
      target.positions.y = Math.round(actor.positions.y - normY);
    }
    // Apply grabbed to target on crit
    if (degree === 'critical-success') {
      if (!target.conditions) target.conditions = [];
      target.conditions.push({ name: 'grabbed', duration: 1, value: 1, source: 'crosscurrent-counter' });
    }
    return {
      success: true,
      message: `🌊⚔️ Crosscurrent Counter! ${actor.name} rolls ${roll}+${athletics}=${total} vs Fort DC ${fortDC}: ${degree === 'critical-success' ? 'Critical ' : ''}Success! Grab removed, ${target.name} pulled adjacent!${degree === 'critical-success' ? ` ${target.name} is now grabbed!` : ''}`,
    };
  }
  return {
    success: true,
    message: `🌊 Crosscurrent Counter! ${actor.name} rolls ${roll}+${athletics}=${total} vs Fort DC ${fortDC}: Failed to counter the grapple.`,
  };
}

/**
 * Rapid Recharge (Magus 10, Free Action)
 * Once per day: free action to recharge Spellstrike.
 */
export function resolveRapidRecharge(ctx: FeatActionContext, actor: Creature): ActionResult {
  if (!ctx.hasFeat(actor, 'Rapid Recharge')) {
    return { success: false, message: `${actor.name} does not have Rapid Recharge.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  const cooldown = actor.conditions?.find(c => c.name === 'rapid-recharge-used');
  if (cooldown) {
    return { success: false, message: `${actor.name} has already used Rapid Recharge today.`, errorCode: 'ALREADY_USED' };
  }

  if (!actor.conditions) actor.conditions = [];
  actor.conditions.push({ name: 'rapid-recharge-used', duration: 'permanent', value: 1, source: 'rapid-recharge' });

  // Remove spellstrike-discharged condition
  const idx = actor.conditions.findIndex(c => c.name === 'spellstrike-discharged');
  if (idx >= 0) {
    actor.conditions.splice(idx, 1);
  }

  return {
    success: true,
    message: `⚡🔮 Rapid Recharge! ${actor.name} taps into arcane reserves to instantly recharge Spellstrike!`,
  };
}

/**
 * Sustaining Steel (Magus 10, Free Action)
 * Trigger: Cast a Spell using a spell slot while in Arcane Cascade.
 * Heal 2 * spell rank HP. Roll to end persistent negative damage.
 */
export function resolveSustainingSteel(ctx: FeatActionContext, actor: Creature): ActionResult {
  if (!ctx.hasFeat(actor, 'Sustaining Steel')) {
    return { success: false, message: `${actor.name} does not have Sustaining Steel.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  const inCascade = actor.conditions?.some(c => c.name === 'arcane-cascade');
  if (!inCascade) {
    return { success: false, message: `${actor.name} must be in Arcane Cascade to use Sustaining Steel.`, errorCode: 'VALIDATION_FAILED' };
  }

  // Determine spell rank from last cast (simplified: use highest available slot rank)
  const spellSlots = (actor as any).spellSlots ?? [];
  const usedSlot = spellSlots.find((s) => s.remaining < s.max);
  const spellLevel = usedSlot?.rank ?? Math.max(1, Math.floor(actor.level / 2));
  const healing = spellLevel * 2;

  actor.currentHealth = Math.min(actor.maxHealth, actor.currentHealth + healing);

  // Roll to end persistent negative damage
  if (actor.conditions) {
    const negIdx = actor.conditions.findIndex(c => c.name === 'persistent-negative');
    if (negIdx >= 0) {
      const endRoll = rollD20();
      if (endRoll >= 15) { // flat DC 15 check
        actor.conditions.splice(negIdx, 1);
      }
    }
  }

  return {
    success: true,
    message: `🗡️💚 Sustaining Steel! ${actor.name} channels spell energy into healing! Recovers ${healing} HP (spell rank ${spellLevel}). HP: ${actor.currentHealth}/${actor.maxHealth}`,
  };
}

/**
 * Vermilion Threads (Magus 10, Reaction)
 * Trigger: You use Arcane Cascade.
 * Create 15-ft burst difficult terrain web. Walk on air within web. Lasts 1 min or until Cascade ends.
 */
export function resolveVermilionThreads(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Vermilion Threads')) {
    return { success: false, message: `${actor.name} does not have Vermilion Threads.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }

  actor.reactionUsed = true;

  if (!actor.conditions) actor.conditions = [];
  actor.conditions.push({ name: 'vermilion-threads', duration: 10, value: 1, source: 'vermilion-threads' });

  // Mark affected area (15-ft burst = 3 squares radius centered on actor)
  if (!(gameState as any).terrainEffects) (gameState as any).terrainEffects = [];
  (gameState as any).terrainEffects.push({
    type: 'difficult-terrain',
    source: 'vermilion-threads',
    center: { x: actor.positions.x, y: actor.positions.y },
    radius: 3,
    duration: 10,
    ownerId: actor.id,
  });

  return {
    success: true,
    message: `🕸️🔴 Vermilion Threads! ${actor.name} sends crimson threads in all directions! 15-ft burst of difficult terrain. ${actor.name} can walk on the threads!`,
  };
}

/**
 * Preternatural Parry (Magus 14, Reaction)
 * Trigger: Targeted by Strike/spell attack, or about to roll save vs spell.
 * +2 circumstance bonus to AC and saves vs triggering effect until start of next turn.
 */
export function resolvePrenternaturalParry(ctx: FeatActionContext, actor: Creature): ActionResult {
  if (!ctx.hasFeat(actor, 'Preternatural Parry')) {
    return { success: false, message: `${actor.name} does not have Preternatural Parry.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (actor.reactionUsed) {
    return { success: false, message: `${actor.name} has already used their reaction this round.`, errorCode: 'REACTION_USED' };
  }

  actor.reactionUsed = true;

  if (!actor.conditions) actor.conditions = [];
  actor.conditions.push({ name: 'preternatural-parry', duration: 1, value: 2, source: 'preternatural-parry' });
  if (!actor.bonuses) actor.bonuses = [];
  actor.bonuses.push({ source: 'preternatural-parry', value: 2, type: 'circumstance', applyTo: 'ac' });
  actor.bonuses.push({ source: 'preternatural-parry', value: 2, type: 'circumstance', applyTo: 'saves' });

  return {
    success: true,
    message: `🗡️🛡️ Preternatural Parry! ${actor.name} snaps their weapon into a defensive position! +2 circumstance to AC and saves vs the triggering effect.`,
  };
}

/**
 * Resounding Cascade (Magus 16, Free Action)
 * Trigger: You use Arcane Cascade.
 * Allies in 5-ft emanation gain base Arcane Cascade damage.
 */
export function resolveResoundingCascade(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Resounding Cascade')) {
    return { success: false, message: `${actor.name} does not have Resounding Cascade.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }

  // Find allies in 5-ft emanation (1 square)
  const allies = gameState.creatures.filter(c =>
    c.id !== actor.id && c.currentHealth > 0 &&
    c.type === 'player' &&
    ctx.calculateDistance(actor.positions, c.positions) <= 1.5
  );

  // Apply base Arcane Cascade damage bonus to allies
  const cascadeDamage = 1; // base Arcane Cascade damage
  for (const ally of allies) {
    if (!ally.conditions) ally.conditions = [];
    ally.conditions.push({ name: 'resounding-cascade', duration: 'permanent', value: cascadeDamage, source: 'resounding-cascade' });
    if (!ally.bonuses) ally.bonuses = [];
    ally.bonuses.push({ source: 'resounding-cascade', value: cascadeDamage, type: 'status', applyTo: 'melee-damage' });
  }

  return {
    success: true,
    message: allies.length > 0
      ? `🔊✨ Resounding Cascade! ${actor.name} resonates arcane energy to ${allies.length} nearby all${allies.length > 1 ? 'ies' : 'y'}! They gain +${cascadeDamage} Arcane Cascade damage.`
      : `🔊 Resounding Cascade! ${actor.name} resonates arcane energy, but no allies are within 5 feet.`,
  };
}

