// ── Level 1 Kineticist Feats ───────────────────────────────

/**
 * Aerial Boomerang (Kineticist 1, 2 actions)
 * Impulse attack 60 ft, 2d4 slashing. Miss → second attack for 1d4.
 */
export function resolveAerialBoomerang(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Aerial Boomerang')) return { success: false, message: `${actor.name} does not have Aerial Boomerang.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 12) return { success: false, message: 'Target beyond 60 feet.', errorCode: 'OUT_OF_RANGE' };
  const impulseLevel = Math.ceil(actor.level / 2);
  const extraDice = Math.max(0, Math.floor((impulseLevel - 1) / 2));
  const mainDice = 2 + extraDice;
  const roll1 = rollD20();
  const atkBonus = ctx.getSkillBonus(actor, 'impulse-attack') || ctx.getSkillBonus(actor, 'class-dc');
  const total1 = roll1 + atkBonus;
  const ac = calculateAC(target);
  if (total1 >= ac) {
    const dmg = rollDamageFormula(`${mainDice}d4`).total;
    const crit = total1 >= ac + 10;
    const finalDmg = crit ? dmg * 2 : dmg;
    target.currentHealth = Math.max(0, target.currentHealth - finalDmg);
    return { success: true, message: `🪃💨 Aerial Boomerang! ${actor.name} rolls ${roll1}+${atkBonus}=${total1} vs AC ${ac}: ${crit ? 'CRITICAL HIT' : 'Hit'}! ${target.name} takes ${finalDmg} slashing damage.` };
  }
  // Miss - second attack
  if (roll1 === 1 || total1 < ac - 10) return { success: true, message: `🪃 Aerial Boomerang! ${actor.name} rolls ${roll1}+${atkBonus}=${total1} vs AC ${ac}: Critical Miss! The boomerang flies wide.` };
  const roll2 = rollD20();
  const total2 = roll2 + atkBonus;
  if (total2 >= ac) {
    const dmg2 = rollDamageFormula(`${1 + extraDice}d4`).total;
    const crit2 = total2 >= ac + 10;
    const finalDmg2 = crit2 ? dmg2 * 2 : dmg2;
    target.currentHealth = Math.max(0, target.currentHealth - finalDmg2);
    return { success: true, message: `🪃💨 Aerial Boomerang curves back! ${actor.name} first ${roll1}+${atkBonus}=${total1} miss, second ${roll2}+${atkBonus}=${total2} vs AC ${ac}: ${crit2 ? 'CRIT' : 'Hit'}! ${finalDmg2} slashing.` };
  }
  return { success: true, message: `🪃 Aerial Boomerang! ${actor.name} first ${roll1}, second ${roll2}: both miss ${target.name}.` };
}

/**
 * Air Cushion (Kineticist 1, Reaction)
 * Trigger: creature within 60 ft falls. Feather fall + in aura: +10 ft Speed.
 */
export function resolveAirCushion(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Air Cushion')) return { success: false, message: `${actor.name} does not have Air Cushion.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  if (actor.reactionUsed) return { success: false, message: `${actor.name} has already used their reaction.`, errorCode: 'REACTION_USED' };
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : actor;
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };
  actor.reactionUsed = true;
  if (!target.conditions) target.conditions = [];
  target.conditions.push({ name: 'feather-fall', duration: 1, value: 1, source: 'air-cushion' });
  const inAura = ctx.calculateDistance(actor.positions, target.positions) <= 2;
  if (inAura) {
    if (!target.bonuses) target.bonuses = [];
    target.bonuses.push({ source: 'air-cushion', value: 10, type: 'status', applyTo: 'speed' });
  }
  return { success: true, message: `🌬️🪶 Air Cushion! ${actor.name} cushions ${target.name}'s fall${inAura ? ' and grants +10 ft Speed' : ''}.` };
}

