/**
 * Deflecting Wave (Kineticist 1, Reaction)
 * Trigger: physical damage to you or ally in aura. Resist = level.
 */
export function resolveDeflectingWave(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Deflecting Wave')) return { success: false, message: `${actor.name} does not have Deflecting Wave.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  if (actor.reactionUsed) return { success: false, message: `${actor.name} has already used their reaction.`, errorCode: 'REACTION_USED' };
  actor.reactionUsed = true;
  const resist = actor.level;
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : actor;
  if (target) {
    if (!target.conditions) target.conditions = [];
    target.conditions.push({ name: 'deflecting-wave', duration: 1, value: resist, source: 'deflecting-wave' });
  }
  return { success: true, message: `🌊🛡️ Deflecting Wave! ${actor.name} grants ${target?.name || 'ally'} resistance ${resist} to physical damage.` };
}

