/**
 * Flying Flame (Kineticist 1, 2 actions)
 * 30-ft path, 1d6 fire basic Reflex.
 */
export function resolveFlyingFlame(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Flying Flame')) return { success: false, message: `${actor.name} does not have Flying Flame.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  const impulseLevel = Math.ceil(actor.level / 2);
  const dice = 1 + Math.max(0, Math.floor((impulseLevel - 1) / 2));
  const classDC = 10 + actor.level + (actor.abilities?.constitution || 0);
  const enemies = gameState.creatures.filter(c => c.type !== 'player' && c.currentHealth > 0 && ctx.calculateDistance(actor.positions, c.positions) <= 6);
  let msgs: string[] = [];
  for (const enemy of enemies) {
    const save = ctx.rollSave(enemy, 'reflex', classDC);
    const baseDmg = rollDamageFormula(`${dice}d6`).total;
    const degree = save.result || save.degree || 'failure';
    let dmg = degree === 'critical-success' ? 0 : degree === 'success' ? Math.floor(baseDmg / 2) : degree === 'critical-failure' ? baseDmg * 2 : baseDmg;
    enemy.currentHealth = Math.max(0, enemy.currentHealth - dmg);
    msgs.push(`${enemy.name}: ${dmg} fire (${degree})`);
  }
  return { success: true, message: `🔥🕊️ Flying Flame! ${actor.name} sends flame on a 30-ft path. ${msgs.length > 0 ? msgs.join(', ') : 'No targets in path.'}` };
}

/**
 * Four Winds (Kineticist 1, 2 actions)
 * Up to 4 allies within 30 ft Stride half Speed.
 */
export function resolveFourWinds(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Four Winds')) return { success: false, message: `${actor.name} does not have Four Winds.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  const allies = gameState.creatures.filter(c => c.type === 'player' && c.currentHealth > 0 && ctx.calculateDistance(actor.positions, c.positions) <= 6).slice(0, 4);
  return { success: true, message: `🌬️🌬️ Four Winds! ${actor.name} sends gusts carrying ${allies.length} allies. Each can Stride up to half Speed (no reactions).` };
}

/**
 * Fresh Produce (Kineticist 1, 1 action)
 * 1d4+1 HP heal + resist 1 void 1 min.
 */
export function resolveFreshProduce(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Fresh Produce')) return { success: false, message: `${actor.name} does not have Fresh Produce.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : actor;
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };
  if (target.conditions?.some(c => c.name === 'fresh-produce-immune')) return { success: false, message: `${target.name} is temporarily immune to Fresh Produce.`, errorCode: 'IMMUNE' };
  const impulseLevel = Math.ceil(actor.level / 2);
  const extraDice = Math.max(0, Math.floor((impulseLevel - 1) / 2));
  const healing = rollDamageFormula(`${1 + extraDice}d4`).total + 1 + extraDice;
  target.currentHealth = Math.min(target.maxHealth, target.currentHealth + healing);
  if (!target.conditions) target.conditions = [];
  target.conditions.push({ name: 'fresh-produce-immune', duration: 100, value: 1, source: 'fresh-produce' });
  return { success: true, message: `🌿🍎 Fresh Produce! ${actor.name} grows fruit. ${target.name} heals ${healing} HP and gains resistance 1 to void.` };
}

