/**
 * Magnetic Pinions (Kineticist 1, 3 actions, Overflow)
 * 3 attacks, 60 ft, 1d4B+1d4P each. +1 vs metal.
 */
export function resolveMagneticPinions(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Magnetic Pinions')) return { success: false, message: `${actor.name} does not have Magnetic Pinions.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  const impulseLevel = Math.ceil(actor.level / 2);
  const extraDice = Math.max(0, Math.floor((impulseLevel - 1) / 2));
  const enemies = gameState.creatures.filter(c => c.type !== 'player' && c.currentHealth > 0 && ctx.calculateDistance(actor.positions, c.positions) <= 12);
  const targets = enemies.slice(0, 3);
  if (targets.length === 0) return { success: false, message: 'No valid targets within 60 feet.', errorCode: 'NO_TARGET' };
  const atkBonus = ctx.getSkillBonus(actor, 'impulse-attack') || ctx.getSkillBonus(actor, 'class-dc');
  let msgs: string[] = [];
  let map = 0;
  for (const t of targets) {
    const roll = rollD20();
    const total = roll + atkBonus - map;
    const ac = calculateAC(t);
    if (total >= ac) {
      const dmg = rollDamageFormula(`${1 + extraDice}d4`).total + rollDamageFormula(`${1 + extraDice}d4`).total;
      const crit = total >= ac + 10;
      const finalDmg = crit ? dmg * 2 : dmg;
      t.currentHealth = Math.max(0, t.currentHealth - finalDmg);
      msgs.push(`${t.name}: ${finalDmg} B+P (${crit ? 'crit' : 'hit'})`);
    } else {
      msgs.push(`${t.name}: miss`);
    }
  }
  return { success: true, message: `🧲📌 Magnetic Pinions! ${actor.name} fires 3 metal shards. ${msgs.join(', ')}` };
}

