/**
 * Ocean's Balm (Kineticist 1, 1 action)
 * Touch: 1d8 HP + resist 2 fire 1 min.
 */
export function resolveOceansBalm(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, "Ocean's Balm")) return { success: false, message: `${actor.name} does not have Ocean's Balm.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : actor;
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };
  if (target.conditions?.some(c => c.name === 'oceans-balm-immune')) return { success: false, message: `${target.name} is temporarily immune.`, errorCode: 'IMMUNE' };
  const impulseLevel = Math.ceil(actor.level / 2);
  const extraDice = Math.max(0, Math.floor((impulseLevel - 1) / 2));
  const healing = rollDamageFormula(`${1 + extraDice}d8`).total;
  const resist = 2 + extraDice;
  target.currentHealth = Math.min(target.maxHealth, target.currentHealth + healing);
  if (!target.conditions) target.conditions = [];
  target.conditions.push({ name: 'oceans-balm-immune', duration: 100, value: 1, source: 'oceans-balm' });
  return { success: true, message: `🌊💚 Ocean's Balm! ${actor.name} heals ${target.name} for ${healing} HP and grants resistance ${resist} to fire for 1 min.` };
}

