/**
 * Calcifying Sand (Kineticist 4, Reaction)
 * Trigger: adjacent ally hit. Reaction to give them +1 circumstance AC, resist = half level.
 */
export function resolveCalcifyingSand(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Calcifying Sand')) return { success: false, message: `${actor.name} does not have Calcifying Sand.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  if (actor.reactionUsed) return { success: false, message: `${actor.name} has already used their reaction.`, errorCode: 'REACTION_USED' };
  actor.reactionUsed = true;
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : null;
  if (!target) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  if (!target.bonuses) target.bonuses = [];
  target.bonuses.push({ source: 'calcifying-sand', value: 1, type: 'circumstance', applyTo: 'ac' });
  const resist = Math.floor(actor.level / 2);
  return { success: true, message: `🏜️🛡️ Calcifying Sand! ${actor.name} coats ${target.name} in hardening sand. +1 AC and resistance ${resist} physical until end of next turn.` };
}

/**
 * Command Elemental (Kineticist 4, 3 actions)
 * Attempt to command an elemental (Will save vs class DC).
 */
export function resolveCommandElemental(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Command Elemental')) return { success: false, message: `${actor.name} does not have Command Elemental.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };
  const classDC = 10 + actor.level + (actor.abilities?.constitution || 0);
  const save = ctx.rollSave(target, 'will', classDC);
  const degree = save.result || save.degree || 'failure';
  if (degree === 'critical-success') return { success: true, message: `🌀⚡ Command Elemental! ${target.name} resists entirely (critical success) and is immune for 24 hours.` };
  if (degree === 'success') return { success: true, message: `🌀⚡ Command Elemental! ${target.name} partially resists (success). Can follow simple commands for 1 round.` };
  if (degree === 'critical-failure') {
    if (!target.conditions) target.conditions = [];
    target.conditions.push({ name: 'commanded', duration: 'permanent', value: 1, source: 'command-elemental' });
    return { success: true, message: `🌀⚡ Command Elemental! ${target.name} is fully under ${actor.name}'s control (critical failure)! Until next dawn.` };
  }
  if (!target.conditions) target.conditions = [];
  target.conditions.push({ name: 'commanded', duration: 10, value: 1, source: 'command-elemental' });
  return { success: true, message: `🌀⚡ Command Elemental! ${target.name} is commanded by ${actor.name} (failure). Obeys for 1 minute.` };
}

/**
 * Igneogenesis (Kineticist 4, 2 actions)
 * Create 20 ft cube of rock/earth within 60 ft. Fill or wall.
 */
