/**
 * Lava Leap (Kineticist 4, 2 actions, Overflow)
 * Leap 40 ft. 2d6 fire damage to each creature you pass. Basic Reflex.
 */
export function resolveLavaLeap(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Lava Leap')) return { success: false, message: `${actor.name} does not have Lava Leap.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  const impulseLevel = Math.ceil(actor.level / 2);
  const dice = 2 + Math.max(0, Math.floor((impulseLevel - 2) / 2));
  const classDC = 10 + actor.level + (actor.abilities?.constitution || 0);
  const enemies = gameState.creatures.filter(c => c.type !== 'player' && c.currentHealth > 0 && ctx.calculateDistance(actor.positions, c.positions) <= 4);
  let msgs: string[] = [];
  for (const enemy of enemies) {
    const save = ctx.rollSave(enemy, 'reflex', classDC);
    const baseDmg = rollDamageFormula(`${dice}d6`).total;
    const degree = save.result || save.degree || 'failure';
    let dmg = degree === 'critical-success' ? 0 : degree === 'success' ? Math.floor(baseDmg / 2) : degree === 'critical-failure' ? baseDmg * 2 : baseDmg;
    enemy.currentHealth = Math.max(0, enemy.currentHealth - dmg);
    msgs.push(`${enemy.name}: ${dmg} fire (${degree})`);
  }
  return { success: true, message: `🌋🦘 Lava Leap! ${actor.name} leaps 40 ft through lava. ${msgs.join(', ') || 'No targets in path.'}` };
}

