/**
 * Flinging Updraft (Kineticist 6, 2 actions)
 * 60 ft range. Launch creature up 40 ft. Fort save vs falling.
 */
export function resolveFlingIngUpdraft(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Flinging Updraft')) return { success: false, message: `${actor.name} does not have Flinging Updraft.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };
  if (target.type === 'player') {
    return { success: true, message: `🌬️⬆️ Flinging Updraft! ${actor.name} launches ${target.name} 40 feet up and 40 feet horizontally on a cushion of air.` };
  }
  const classDC = 10 + actor.level + (actor.abilities?.constitution || 0);
  const save = ctx.rollSave(target, 'fortitude', classDC);
  const degree = save.result || save.degree || 'failure';
  if (degree === 'success' || degree === 'critical-success') return { success: true, message: `🌬️⬆️ Flinging Updraft! ${target.name} resists (${degree}).` };
  const fallDmg = degree === 'critical-failure' ? rollDamageFormula('8d6').total : rollDamageFormula('4d6').total;
  target.currentHealth = Math.max(0, target.currentHealth - fallDmg);
  return { success: true, message: `🌬️⬆️ Flinging Updraft! ${target.name} is launched 40 ft, then falls for ${fallDmg} damage (${degree})!` };
}

/**
 * Sand Snatcher (Kineticist 6, 2 actions)
 * 30 ft range. Target must Fort save or immobilized 1 round (+1 on crit fail).
 */
export function resolveSandSnatcher(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Sand Snatcher')) return { success: false, message: `${actor.name} does not have Sand Snatcher.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };
  const classDC = 10 + actor.level + (actor.abilities?.constitution || 0);
  const save = ctx.rollSave(target, 'fortitude', classDC);
  const degree = save.result || save.degree || 'failure';
  if (degree === 'critical-success' || degree === 'success') return { success: true, message: `🏜️🤚 Sand Snatcher! ${target.name} resists (${degree}).` };
  if (!target.conditions) target.conditions = [];
  const dur = degree === 'critical-failure' ? 2 : 1;
  target.conditions.push({ name: 'immobilized', duration: dur, value: 1, source: 'sand-snatcher' });
  return { success: true, message: `🏜️🤚 Sand Snatcher! ${target.name} is trapped in sand—immobilized ${dur} round(s) (${degree})!` };
}

/**
 * Weight of Stone (Kineticist 6, 2 actions)
 * 60 ft range. Target Fort save: fail = encumbered 1 min, crit fail = immobilized.
 */
export function resolveWeightOfStone(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Weight of Stone')) return { success: false, message: `${actor.name} does not have Weight of Stone.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };
  const classDC = 10 + actor.level + (actor.abilities?.constitution || 0);
  const save = ctx.rollSave(target, 'fortitude', classDC);
  const degree = save.result || save.degree || 'failure';
  if (degree === 'critical-success' || degree === 'success') return { success: true, message: `🪨⬇️ Weight of Stone! ${target.name} resists the pull (${degree}).` };
  if (!target.conditions) target.conditions = [];
  if (degree === 'critical-failure') {
    target.conditions.push({ name: 'immobilized', duration: 10, value: 1, source: 'weight-of-stone' });
    target.conditions.push({ name: 'encumbered', duration: 10, value: 1, source: 'weight-of-stone' });
    return { success: true, message: `🪨⬇️ Weight of Stone! ${target.name} is crushed—immobilized and encumbered for 1 min (critical failure)!` };
  }
  target.conditions.push({ name: 'encumbered', duration: 10, value: 1, source: 'weight-of-stone' });
  return { success: true, message: `🪨⬇️ Weight of Stone! ${target.name} is encumbered for 1 min (failure).` };
}

