/**
 * Volcanic Escape (Kineticist 6, Reaction)
 * Trigger: hit by melee. Stride half Speed + 1d6 fire to attacker basic Reflex.
 */
export function resolveVolcanicEscape(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Volcanic Escape')) return { success: false, message: `${actor.name} does not have Volcanic Escape.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  if (actor.reactionUsed) return { success: false, message: `${actor.name} has already used their reaction.`, errorCode: 'REACTION_USED' };
  actor.reactionUsed = true;
  const impulseLevel = Math.ceil(actor.level / 2);
  const dice = 1 + Math.max(0, Math.floor((impulseLevel - 3) / 2));
  const classDC = 10 + actor.level + (actor.abilities?.constitution || 0);
  let attackerMsg = '';
  if (targetId) {
    const attacker = gameState.creatures.find(c => c.id === targetId);
    if (attacker) {
      const save = ctx.rollSave(attacker, 'reflex', classDC);
      const baseDmg = rollDamageFormula(`${dice}d6`).total;
      const degree = save.result || save.degree || 'failure';
      let dmg = degree === 'critical-success' ? 0 : degree === 'success' ? Math.floor(baseDmg / 2) : degree === 'critical-failure' ? baseDmg * 2 : baseDmg;
      attacker.currentHealth = Math.max(0, attacker.currentHealth - dmg);
      attackerMsg = ` ${attacker.name} takes ${dmg} fire (${degree}).`;
    }
  }
  return { success: true, message: `🌋💨 Volcanic Escape! ${actor.name} erupts and Strides half Speed.${attackerMsg}` };
}

/**
 * Consume Power (Kineticist 6, Reaction)
 * Trigger: would be damaged by your element. Negate damage and fuel next impulse.
 */
export function resolveConsumePower(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Consume Power')) return { success: false, message: `${actor.name} does not have Consume Power.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  if (actor.reactionUsed) return { success: false, message: `${actor.name} has already used their reaction.`, errorCode: 'REACTION_USED' };
  actor.reactionUsed = true;
  if (!actor.conditions) actor.conditions = [];
  actor.conditions.push({ name: 'consume-power', duration: 2, value: 1, source: 'consume-power' });
  return { success: true, message: `⚡🔋 Consume Power! ${actor.name} absorbs elemental energy, negating the damage! Next impulse is empowered.` };
}

