/**
 * Desert Wind (Kineticist 6, 2 actions, Overflow)
 * 30-ft cone. 4d4 fire basic Reflex + dazzled 1 round (fail) or blinded 1 round (crit fail).
 */
export function resolveDesertWind(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Desert Wind')) return { success: false, message: `${actor.name} does not have Desert Wind.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  const impulseLevel = Math.ceil(actor.level / 2);
  const dice = 4 + Math.max(0, Math.floor((impulseLevel - 3) / 2));
  const classDC = 10 + actor.level + (actor.abilities?.constitution || 0);
  const enemies = gameState.creatures.filter(c => c.type !== 'player' && c.currentHealth > 0 && ctx.calculateDistance(actor.positions, c.positions) <= 6);
  let msgs: string[] = [];
  for (const enemy of enemies) {
    const save = ctx.rollSave(enemy, 'reflex', classDC);
    const baseDmg = rollDamageFormula(`${dice}d4`).total;
    const degree = save.result || save.degree || 'failure';
    let dmg = degree === 'critical-success' ? 0 : degree === 'success' ? Math.floor(baseDmg / 2) : degree === 'critical-failure' ? baseDmg * 2 : baseDmg;
    enemy.currentHealth = Math.max(0, enemy.currentHealth - dmg);
    if (!enemy.conditions) enemy.conditions = [];
    if (degree === 'failure') enemy.conditions.push({ name: 'dazzled', duration: 1, value: 1, source: 'desert-wind' });
    if (degree === 'critical-failure') enemy.conditions.push({ name: 'blinded', duration: 1, value: 1, source: 'desert-wind' });
    msgs.push(`${enemy.name}: ${dmg} fire (${degree})`);
  }
  return { success: true, message: `🏜️💨 Desert Wind! ${actor.name} unleashes searing sand. ${msgs.join(', ') || 'No targets.'}` };
}

/**
 * Elemental Artillery (Kineticist 6, 2 actions)
 * 120-ft range impulse attack. 2d10 + element damage.
 */
export function resolveElementalArtillery(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Elemental Artillery')) return { success: false, message: `${actor.name} does not have Elemental Artillery.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 24) return { success: false, message: 'Target beyond 120 feet.', errorCode: 'OUT_OF_RANGE' };
  const impulseLevel = Math.ceil(actor.level / 2);
  const extraDice = Math.max(0, Math.floor((impulseLevel - 3) / 2));
  const atkBonus = ctx.getSkillBonus(actor, 'impulse-attack') || ctx.getSkillBonus(actor, 'class-dc');
  const roll = rollD20();
  const total = roll + atkBonus;
  const ac = calculateAC(target);
  if (total >= ac) {
    const dmg = rollDamageFormula(`${2 + extraDice}d10`).total;
    const crit = total >= ac + 10;
    const finalDmg = crit ? dmg * 2 : dmg;
    target.currentHealth = Math.max(0, target.currentHealth - finalDmg);
    return { success: true, message: `🎯💥 Elemental Artillery! ${actor.name} rolls ${roll}+${atkBonus}=${total} vs AC ${ac}: ${crit ? 'CRITICAL' : 'Hit'}! ${target.name} takes ${finalDmg} damage at 120 ft range.` };
  }
  return { success: true, message: `🎯 Elemental Artillery! ${actor.name} rolls ${roll}+${atkBonus}=${total} vs AC ${ac}: Miss!` };
}

/**
 * Jagged Berms (Kineticist 6, 3 actions)
 * Two 5-ft wide × 10 ft tall earth walls within 60 ft. Creatures adjacent take 2d6 slashing.
 */
