/**
 * Tree of Duality (Kineticist 6, 3 actions)
 * Plant a tree within 30 ft. Choose: fruit (heal 3d8) or thorns (3d6 piercing 15-ft cone).
 */
export function resolveTreeOfDuality(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Tree of Duality')) return { success: false, message: `${actor.name} does not have Tree of Duality.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  const impulseLevel = Math.ceil(actor.level / 2);
  const dice = 3 + Math.max(0, Math.floor((impulseLevel - 3) / 2));
  // Healing mode for allies
  const allies = gameState.creatures.filter(c => c.type === 'player' && c.currentHealth > 0 && c.currentHealth < c.maxHealth && ctx.calculateDistance(actor.positions, c.positions) <= 6);
  if (allies.length > 0) {
    const healing = rollDamageFormula(`${dice}d8`).total;
    for (const ally of allies.slice(0, 1)) {
      ally.currentHealth = Math.min(ally.maxHealth, ally.currentHealth + healing);
    }
    return { success: true, message: `🌳🍎 Tree of Duality (Fruit)! ${actor.name} grows a tree. ${allies[0].name} plucks fruit and heals ${healing} HP. Sustain 1 min.` };
  }
  return { success: true, message: `🌳🌹 Tree of Duality! ${actor.name} grows a magical tree within 30 ft. Choose fruit (heal) or thorns (damage) each round. Sustain 1 min.` };
}

