/**
 * Purify Element (Kineticist 8, 2 actions)
 * 30-ft emanation. End persistent elemental damage on allies.
 */
export function resolvePurifyElement(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Purify Element')) return { success: false, message: `${actor.name} does not have Purify Element.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  const allies = gameState.creatures.filter(c => c.type === 'player' && c.currentHealth > 0 && ctx.calculateDistance(actor.positions, c.positions) <= 6);
  let healed: string[] = [];
  for (const ally of allies) {
    if (ally.conditions) {
      const before = ally.conditions.length;
      ally.conditions = ally.conditions.filter(c => !c.name.startsWith('persistent-'));
      if (ally.conditions.length < before) healed.push(ally.name);
    }
  }
  return { success: true, message: `✨🌀 Purify Element! ${actor.name} purges elemental damage from allies in 30 ft. ${healed.length > 0 ? `Cleansed: ${healed.join(', ')}` : 'No persistent damage found.'}` };
}

