/**
 * Kindle Inner Flames (Kineticist 8, 2 actions)
 * 30 ft range. Target Will save. Fail: 4d6 fire + frightened 1. Crit fail: 8d6 + frightened 2.
 */
export function resolveKindleInnerFlames(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Kindle Inner Flames')) return { success: false, message: `${actor.name} does not have Kindle Inner Flames.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };
  const impulseLevel = Math.ceil(actor.level / 2);
  const dice = 4 + Math.max(0, Math.floor((impulseLevel - 4) / 2));
  const classDC = 10 + actor.level + (actor.abilities?.constitution || 0);
  const save = ctx.rollSave(target, 'will', classDC);
  const degree = save.result || save.degree || 'failure';
  if (degree === 'critical-success' || degree === 'success') return { success: true, message: `🔥😱 Kindle Inner Flames! ${target.name} resists (${degree}).` };
  const baseDmg = rollDamageFormula(`${dice}d6`).total;
  const dmg = degree === 'critical-failure' ? baseDmg * 2 : baseDmg;
  target.currentHealth = Math.max(0, target.currentHealth - dmg);
  if (!target.conditions) target.conditions = [];
  target.conditions.push({ name: 'frightened', duration: 1, value: degree === 'critical-failure' ? 2 : 1, source: 'kindle-inner-flames' });
  return { success: true, message: `🔥😱 Kindle Inner Flames! ${target.name} takes ${dmg} fire and is frightened ${degree === 'critical-failure' ? 2 : 1} (${degree}).` };
}

