export function resolveAmmunitionThaumaturgy(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // Passive: can reload with implement hand
  if (!actor.conditions) actor.conditions = [];
  const already = actor.conditions.find(c => c.name === 'ammunition-thaumaturgy');
  if (already) return { success: true, message: `${actor.name} already has Ammunition Thaumaturgy active.` };
  actor.conditions.push({ name: 'ammunition-thaumaturgy', duration: 'permanent', source: 'Ammunition Thaumaturgy' });
  return { success: true, message: `🔫🔮 ${actor.name} activates Ammunition Thaumaturgy — can reload with implement hand.` };
}

export function resolveDiverseLore(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // Recall Knowledge with Esoteric Lore at -2 on any topic
  const bonus = ctx.getSkillBonus(actor, 'esoteric-lore') - 2;
  const roll = rollD20();
  const total = roll + bonus;
  return { success: true, message: `📚🔮 ${actor.name} uses Diverse Lore (Esoteric Lore at -2)! Rolls ${roll}+${bonus}=${total} to Recall Knowledge on any topic.` };
}

export function resolveDivineDisharmony(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Divine Disharmony requires a target.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 12) return { success: false, message: 'Target must be within 60 feet.' };
  const skill = Math.max(ctx.getSkillBonus(actor, 'deception'), ctx.getSkillBonus(actor, 'intimidation'));
  const roll = rollD20();
  const total = roll + skill;
  const dc = ctx.getWillDC(target);
  // +2 bonus vs divine devoted
  const isDivine = (target as any).traits?.some((t: string) => ['celestial', 'fiend', 'monitor', 'divine'].includes(t.toLowerCase()));
  const bonus = isDivine ? 2 : 0;
  const finalTotal = total + bonus;
  const result = getDegreeOfSuccess(finalTotal, dc, roll);
  if (result === 'critical-success') {
    if (!target.conditions) target.conditions = [];
    target.conditions.push({ name: 'off-guard', duration: 2, source: 'Divine Disharmony' });
    return { success: true, message: `⚡🔮 Divine Disharmony! ${actor.name} rolls ${roll}+${skill}${bonus ? '+2' : ''}=${finalTotal} vs Will DC ${dc}: Critical Success! ${target.name} is off-guard until end of next turn!` };
  } else if (result === 'success') {
    if (!target.conditions) target.conditions = [];
    target.conditions.push({ name: 'off-guard', duration: 1, source: 'Divine Disharmony' });
    return { success: true, message: `⚡🔮 Divine Disharmony! ${actor.name} rolls ${roll}+${skill}${bonus ? '+2' : ''}=${finalTotal} vs Will DC ${dc}: Success! ${target.name} is off-guard until end of this turn!` };
  }
  return { success: true, message: `⚡🔮 Divine Disharmony! ${actor.name} rolls ${roll}+${skill}${bonus ? '+2' : ''}=${finalTotal} vs Will DC ${dc}: Failure — no effect.` };
}

