export function resolveRootToLife(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Root to Life requires an adjacent dying target.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 1) return { success: false, message: 'Target must be adjacent.' };
  const dyingCond = target.conditions?.find((c) => c.name === 'dying');
  if (!dyingCond) return { success: false, message: `${target.name} is not dying.` };
  target.conditions = (target.conditions ?? []).filter((c) => c.name !== 'dying');
  if (!target.conditions) target.conditions = [];
  target.conditions.push({ name: 'unconscious', duration: 'permanent', source: 'Root to Life' });
  target.currentHealth = 0;
  return { success: true, message: `🌿💚 Root to Life! ${actor.name} stabilizes ${target.name} — no longer dying, unconscious at 0 HP.` };
}

