export function resolveImplementsAssault(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const enemies = gameState.creatures.filter(c => c.type !== 'player' && c.currentHealth > 0);
  const inRange = enemies.filter(e => ctx.calculateDistance(actor.positions, e.positions) <= 6);
  let messages: string[] = [`⚔️🔮 ${actor.name} unleashes Implement's Assault — striking all enemies within 30 ft!`];
  inRange.forEach(enemy => {
    const result = ctx.resolveStrike(actor, gameState, enemy.id);
    messages.push(`  vs ${enemy.name}: ${result.message}`);
  });
  return { success: true, message: messages.join('\n') };
}

