// ── Level 1 ──────────────────────────────────────────────────

export function resolveBrilliantFlash(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Brilliant Flash requires a target.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 6) return { success: false, message: 'Target must be within 30 feet.' };
  const dc = ctx.getFortitudeDC(target);
  const roll = rollD20();
  const classDC = ctx.getSkillBonus(actor, 'class-dc');
  // Uses class DC vs Fortitude
  const result = getDegreeOfSuccess(classDC, dc, roll);
  if (result === 'critical-success' || result === 'success') {
    if (!target.conditions) target.conditions = [];
    target.conditions.push({ name: 'dazzled', duration: result === 'critical-success' ? 2 : 1, source: 'Brilliant Flash' });
    return { success: true, message: `✨🛡️ Brilliant Flash! ${actor.name}'s shield dazzles ${target.name} — dazzled ${result === 'critical-success' ? 'until end of next turn' : 'for 1 round'}!` };
  }
  return { success: true, message: `✨🛡️ ${actor.name} uses Brilliant Flash but ${target.name} resists.` };
}

export function resolveDazzlingFlash(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // 15-foot cone dazzle
  const enemies = gameState.creatures.filter(c => c.type !== 'player' && ctx.calculateDistance(actor.positions, c.positions) <= 3);
  let dazzled = 0;
  enemies.forEach(e => {
    const dc = ctx.getFortitudeDC(e);
    const roll = rollD20();
    const classDC = ctx.getSkillBonus(actor, 'class-dc');
    const result = getDegreeOfSuccess(classDC, dc, roll);
    if (result === 'critical-success' || result === 'success') {
      if (!e.conditions) e.conditions = [];
      e.conditions.push({ name: 'dazzled', duration: result === 'critical-success' ? 2 : 1, source: 'Dazzling Flash' });
      dazzled++;
    }
  });
  return { success: true, message: `✨🛡️ Dazzling Flash! ${actor.name} dazzles ${dazzled}/${enemies.length} enemies in a 15-ft cone!` };
}

export function resolveDefensiveAdvance(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // Step + Raise Shield
  ctx.resolveStep(actor, gameState, null);
  if (!actor.conditions) actor.conditions = [];
  actor.conditions.push({ name: 'shield-raised', duration: 1, value: 2, source: 'Defensive Advance' });
  return { success: true, message: `🛡️🦶 Defensive Advance! ${actor.name} Steps and Raises Shield (+2 AC).` };
}

