export function resolveIronRepercussions(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Iron Repercussions requires a triggering attacker.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  // Apply resistance to the attack + deal spirit damage
  const levelDmg = Math.max(2, Math.floor(actor.level / 2));
  if (target.currentHealth > 0) {
    target.currentHealth = Math.max(0, target.currentHealth - levelDmg);
    if (target.currentHealth <= 0) initDying(target);
  }
  return { success: true, message: `⚔️🛡️ Iron Repercussions! ${actor.name}'s divine shield deals ${levelDmg} spirit damage to ${target.name}! (HP: ${target.currentHealth}/${target.maxHealth})` };
}

export function resolveNimbleReprisal(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Nimble Reprisal requires a triggering attacker.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 1) return { success: false, message: 'Must be adjacent for reprisal Strike.' };
  const strikeResult = ctx.resolveStrike(actor, gameState, targetId);
  return { success: true, message: `💨🛡️ Nimble Reprisal! ${actor.name} retaliates!\n${strikeResult.message}` };
}

