export function resolveViciousVengeance(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Vicious Vengeance requires a triggering attacker.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 1) {
    ctx.resolveStep(actor, gameState, null);
    return { success: true, message: `🔥🛡️ Vicious Vengeance! ${actor.name} moves closer and deals persistent spirit damage on next Strike.` };
  }
  const levelDmg = Math.max(1, Math.floor(actor.level / 4));
  if (!target.conditions) target.conditions = [];
  target.conditions.push({ name: 'persistent-spirit-damage', duration: 3, value: levelDmg, source: 'Vicious Vengeance' });
  return { success: true, message: `🔥🛡️ Vicious Vengeance! ${actor.name} marks ${target.name} with persistent ${levelDmg} spirit damage!` };
}

