export function resolveAuraOfCourage(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const allies = gameState.creatures.filter(c => c.type === 'player' && c.id !== actor.id);
  const inRange = allies.filter(a => ctx.calculateDistance(actor.positions, a.positions) <= 3);
  let cured = 0;
  inRange.forEach(ally => {
    if (!ally.conditions) ally.conditions = [];
    const fright = ally.conditions.find((c) => c.name === 'frightened');
    if (fright && fright.value) {
      fright.value = Math.max(0, fright.value - 1);
      if (fright.value <= 0) ally.conditions = ally.conditions.filter((c) => c.name !== 'frightened');
      cured++;
    }
  });
  return { success: true, message: `🦁🛡️ Aura of Courage! ${cured} allies in 15 ft reduce frightened by 1. All allies in range can't be frightened above 3.` };
}

export function resolveAuraOfDespair(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const enemies = gameState.creatures.filter(c => c.type !== 'player');
  const inRange = enemies.filter(e => ctx.calculateDistance(actor.positions, e.positions) <= 3);
  inRange.forEach(e => {
    if (!e.conditions) e.conditions = [];
    e.conditions.push({ name: 'aura-despair', duration: 1, value: 1, source: 'Aura of Despair' });
  });
  return { success: true, message: `😰🛡️ Aura of Despair! ${inRange.length} enemies in 15 ft take -1 status penalty to saves.` };
}

export function resolveCruelty(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Cruelty requires a target you are striking.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  if (!target.conditions) target.conditions = [];
  target.conditions.push({ name: 'sickened', duration: 2, value: 1, source: 'Cruelty' });
  return { success: true, message: `💀🛡️ Cruelty! ${actor.name}'s touch of corruption leaves ${target.name} sickened 1!` };
}

export function resolveMercy(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Mercy requires a target.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const removable = ['frightened', 'sickened'];
  let removed = '';
  if (target.conditions) {
    for (const cName of removable) {
      const idx = target.conditions.findIndex((c) => c.name === cName);
      if (idx >= 0) {
        removed = cName;
        target.conditions.splice(idx, 1);
        break;
      }
    }
  }
  return { success: true, message: removed
    ? `💚🙏 Mercy! ${actor.name} removes ${removed} from ${target.name} with Lay on Hands!`
    : `💚🙏 Mercy! ${actor.name} heals ${target.name} via Lay on Hands (no removable conditions present).` };
}

