export function resolveBlessedCounterstrike(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Blessed Counterstrike requires an attacker target.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 1) return { success: false, message: 'Target must be in melee reach.' };
  const result = ctx.resolveStrike(actor, gameState, targetId);
  return { success: true, message: `⚡✨ Blessed Counterstrike! ${actor.name} retaliates with divine fury!\n${result.message}` };
}

export function resolveChampionsSacrifice(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: "Champion's Sacrifice requires an ally." };
  const ally = gameState.creatures.find(c => c.id === targetId);
  if (!ally) return { success: false, message: 'Ally not found.' };
  const dist = ctx.calculateDistance(actor.positions, ally.positions);
  if (dist > 6) return { success: false, message: 'Ally must be within 30 feet.' };
  return { success: true, message: `💖🛡️ Champion's Sacrifice! ${actor.name} takes the damage meant for ${ally.name} — redirecting the attack to themselves!` };
}

