export function resolveDivineWall(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const allies = gameState.creatures.filter(c => c.type === 'player' && c.id !== actor.id);
  const adjacent = allies.filter(a => ctx.calculateDistance(actor.positions, a.positions) <= 1);
  adjacent.forEach(ally => {
    if (!ally.conditions) ally.conditions = [];
    ally.conditions.push({ name: 'divine-wall', duration: 1, value: 1, source: 'Divine Wall' });
  });
  return { success: true, message: `🧱🛡️ Divine Wall! ${actor.name} blocks movement past — ${adjacent.length} adjacent allies gain cover (+1 AC).` };
}

