export function resolveInstrumentOfSlaughter(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Instrument of Slaughter requires a target.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const strikeResult = ctx.resolveStrike(actor, gameState, targetId);
  if (strikeResult.hit || strikeResult.success) {
    const bonusDmg = rollDamageFormula('6d6').total;
    if (target.currentHealth > 0) {
      target.currentHealth = Math.max(0, target.currentHealth - bonusDmg);
      if (target.currentHealth <= 0) initDying(target);
    }
    return { success: true, message: `${strikeResult.message}\n⚔️💀 Instrument of Slaughter! Extra 6d6=${bonusDmg} spirit damage! ${target.name} HP: ${target.currentHealth}/${target.maxHealth}` };
  }
  return strikeResult;
}

