export function resolveRejuvenatingTouch(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Rejuvenating Touch requires an ally.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const healAmt = rollDamageFormula('6d6').total;
  target.currentHealth = Math.min(target.maxHealth, target.currentHealth + healAmt);
  // Remove one condition
  let removed = '';
  if (target.conditions && target.conditions.length > 0) {
    const removable = target.conditions.find((c) => ['enfeebled','clumsy','drained','stupefied'].includes(c.name));
    if (removable) {
      removed = removable.name;
      target.conditions = target.conditions.filter((c) => c !== removable);
    }
  }
  return { success: true, message: `💚✨ Rejuvenating Touch! ${actor.name} heals ${target.name} for ${healAmt} HP!${removed ? ` Also removes ${removed}!` : ''} (HP: ${target.currentHealth}/${target.maxHealth})` };
}

