export function resolveUltimateMercy(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Ultimate Mercy requires a dead ally.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  target.currentHealth = 1;
  if (target.conditions) {
    target.conditions = target.conditions.filter((c) => c.name !== 'dying' && c.name !== 'dead' && c.name !== 'unconscious');
  }
  if (!target.conditions) target.conditions = [];
  target.conditions.push({ name: 'wounded', duration: 'permanent', value: 1, source: 'Ultimate Mercy' });
  return { success: true, message: `💚👑 Ultimate Mercy! ${actor.name} RAISES ${target.name} FROM THE DEAD! Restored to 1 HP, wounded 1. (Costs 2 focus points.)` };
}

