// ── Level 6 ──────────────────────────────────────────────────

export function resolveConnectTheDots(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Connect the Dots requires a non-allied target.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dc = Math.max(ctx.getWillDC(target), ctx.getPerceptionDC(target));
  const roll = rollD20();
  const percBonus = ctx.getSkillBonus(actor, 'perception');
  const total = roll + percBonus;
  const result = getDegreeOfSuccess(total, dc, roll);
  if (result === 'critical-success') {
    const allies = gameState.creatures.filter(c => c.type === 'player' && c.id !== actor.id);
    allies.forEach(a => {
      if (!a.conditions) a.conditions = [];
      a.conditions.push({ name: 'connect-the-dots', duration: 1, value: 2, source: `Connect the Dots (${target.name})` });
    });
    return { success: true, message: `🔗🔍 Connect the Dots! ${actor.name}: ${roll}+${percBonus}=${total} vs DC ${dc}: Critical Success! All allies gain investigation bonus vs ${target.name} for all checks!` };
  } else if (result === 'success') {
    const allies = gameState.creatures.filter(c => c.type === 'player' && c.id !== actor.id);
    allies.forEach(a => {
      if (!a.conditions) a.conditions = [];
      a.conditions.push({ name: 'connect-the-dots', duration: 1, value: 1, source: `Connect the Dots (${target.name})` });
    });
    return { success: true, message: `🔗🔍 Connect the Dots! ${actor.name}: ${roll}+${percBonus}=${total} vs DC ${dc}: Success! Allies gain investigation bonus for next check vs ${target.name}!` };
  } else if (result === 'critical-failure') {
    if (!actor.conditions) actor.conditions = [];
    actor.conditions.push({ name: 'stupefied', duration: 1, value: 1, source: 'Connect the Dots' });
    return { success: false, message: `🔗🔍 Connect the Dots! ${actor.name}: ${roll}+${percBonus}=${total} vs DC ${dc}: Critical Failure! ${actor.name} is stupefied 1!` };
  }
  return { success: false, message: `🔗🔍 Connect the Dots! ${actor.name}: ${roll}+${percBonus}=${total} vs DC ${dc}: Failure.` };
}

