export function resolveShareTincture(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Share Tincture requires an adjacent ally.' };
  const ally = gameState.creatures.find(c => c.id === targetId);
  if (!ally) return { success: false, message: 'Ally not found.' };
  const dist = ctx.calculateDistance(actor.positions, ally.positions);
  if (dist > 1) return { success: false, message: 'Ally must be adjacent (or throw).' };
  return { success: true, message: `⚗️🤝 Share Tincture! ${actor.name} creates and passes a quick tincture to ${ally.name}!` };
}

export function resolveSurgicalShock(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Surgical Shock requires a target.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 1) return { success: false, message: 'Target must be adjacent.' };
  const medBonus = ctx.getSkillBonus(actor, 'medicine');
  const roll = rollD20();
  const total = roll + medBonus;
  const dc = ctx.getFortitudeDC(target);
  const result = getDegreeOfSuccess(total, dc, roll);
  if (result === 'critical-success') {
    if (!target.conditions) target.conditions = [];
    target.conditions.push({ name: 'stupefied', duration: 1, value: 3, source: 'Surgical Shock' });
    return { success: true, message: `🔪⚡ Surgical Shock! ${actor.name} rolls Medicine ${roll}+${medBonus}=${total} vs Fort DC ${dc}: Critical Success! ${target.name} is stupefied 3!` };
  } else if (result === 'success') {
    if (!target.conditions) target.conditions = [];
    target.conditions.push({ name: 'stupefied', duration: 1, value: 2, source: 'Surgical Shock' });
    return { success: true, message: `🔪⚡ Surgical Shock! ${actor.name} rolls Medicine ${roll}+${medBonus}=${total} vs Fort DC ${dc}: Success! ${target.name} is stupefied 2!` };
  } else if (result === 'failure') {
    if (!actor.conditions) actor.conditions = [];
    actor.conditions.push({ name: 'surgical-shock-bonus', duration: 1, value: 1, source: 'Surgical Shock' });
    return { success: true, message: `🔪⚡ Surgical Shock! ${actor.name} rolls Medicine ${roll}+${medBonus}=${total} vs Fort DC ${dc}: Failure — gains +1 to next attack vs ${target.name}.` };
  }
  return { success: false, message: `🔪⚡ Surgical Shock! ${actor.name} rolls Medicine ${roll}+${medBonus}=${total} vs Fort DC ${dc}: Critical Failure — triggers manipulate reactions!` };
}

