export function resolveScatterSwarm(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Scatter Swarm requires a swarm target sharing space with your familiar.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dmg = Math.max(5, actor.level);
  if (target.currentHealth > 0) {
    target.currentHealth = Math.max(0, target.currentHealth - dmg);
    if (target.currentHealth <= 0) initDying(target);
  }
  return { success: true, message: `🐝🧹 Scatter Swarm! ${actor.name}'s familiar disperses ${target.name} for ${dmg} damage (area weakness)! HP: ${target.currentHealth}/${target.maxHealth}` };
}

