export function resolveSympatheticStrike(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Sympathetic Strike requires a target.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const strikeResult = ctx.resolveStrike(actor, gameState, targetId);
  if (strikeResult.hit || strikeResult.success) {
    if (!target.conditions) target.conditions = [];
    const penalty = strikeResult.critical ? 2 : 1;
    target.conditions.push({ name: 'sympathetic-link', duration: 1, value: penalty, source: 'Sympathetic Strike' });
    return { success: true, message: `${strikeResult.message}\n🧹🎯 Sympathetic Strike! ${target.name} takes -${penalty} circumstance to saves vs hexes!` };
  }
  return strikeResult;
}

