export function resolvePatronsPresence(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const enemies = gameState.creatures.filter(c => c.type !== 'player' && ctx.calculateDistance(actor.positions, c.positions) <= 3);
  enemies.forEach(e => {
    const saveResult = ctx.rollSave(e, 'will', ctx.getSkillBonus(actor, 'class-dc'));
    if (saveResult.degree === 'failure') {
      if (!e.conditions) e.conditions = [];
      e.conditions.push({ name: 'stupefied', duration: 1, value: 2, source: "Patron's Presence" });
    } else if (saveResult.degree === 'critical-failure') {
      if (!e.conditions) e.conditions = [];
      e.conditions.push({ name: 'stupefied', duration: 1, value: 3, source: "Patron's Presence" });
    }
  });
  return { success: true, message: `👹🧹 Patron's Presence! ${actor.name}'s familiar manifests patron's aura — ${enemies.length} enemies in 15 ft must save vs stupefied!` };
}

