export function resolvePatronsClaim(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: "Patron's Claim requires a target within 30 ft." };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 6) return { success: false, message: 'Target must be within 30 ft.' };
  const dmg = rollDamageFormula('10d10').total;
  const saveResult = ctx.rollSave(target, 'fortitude', ctx.getSkillBonus(actor, 'class-dc'));
  let finalDmg = dmg;
  if (saveResult.degree === 'critical-success') finalDmg = 0;
  else if (saveResult.degree === 'success') finalDmg = Math.floor(dmg / 2);
  else if (saveResult.degree === 'critical-failure') finalDmg = dmg * 2;
  if (finalDmg > 0 && target.currentHealth > 0) {
    target.currentHealth = Math.max(0, target.currentHealth - finalDmg);
    if (target.currentHealth <= 0) initDying(target);
  }
  if (saveResult.degree === 'failure') {
    if (!target.conditions) target.conditions = [];
    target.conditions.push({ name: 'drained', duration: 'permanent', value: 2, source: "Patron's Claim" });
  } else if (saveResult.degree === 'critical-failure') {
    if (!target.conditions) target.conditions = [];
    target.conditions.push({ name: 'drained', duration: 'permanent', value: 4, source: "Patron's Claim" });
  }
  return { success: true, message: `👹💀 Patron's Claim! ${actor.name}'s patron reaches for ${target.name}: 10d10 spirit — ${saveResult.degree}, ${finalDmg} dmg!${saveResult.degree === 'failure' ? ' Drained 2!' : saveResult.degree === 'critical-failure' ? ' Drained 4!' : ''} (HP: ${target.currentHealth}/${target.maxHealth})` };
}

