export function resolveCrushingGrab(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 5) return { success: false, message: `${target.name} is out of melee range.` };
  const atkBonus = ctx.getSkillBonus(actor, 'athletics');
  const roll = rollD20();
  const dc = ctx.getFortitudeDC(target);
  const total = roll + atkBonus;
  const degree = getDegreeOfSuccess(roll, total, dc);
  if (degree === 'success' || degree === 'critical-success') {
    const dmgDice = rollDamageFormula('1d6');
    target.currentHealth -= dmgDice.total;
    target.conditions = target.conditions || [];
    target.conditions.push({ name: 'Grabbed', duration: 1, source: 'Crushing Grab' });
    return { success: true, message: `💪 ${actor.name} Crushing Grabs ${target.name}! Grabbed + ${dmgDice.total} B damage (${roll}+${atkBonus}=${total} vs DC ${dc}).` };
  }
  return { success: false, message: `${actor.name} fails to Crushing Grab ${target.name} (${roll}+${atkBonus}=${total} vs DC ${dc}).` };
}

