export function resolveMonkStandStill(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const atkBonus = calculateAttackBonus(actor);
  const roll = rollD20();
  const ac = calculateAC(target);
  const total = roll + atkBonus;
  if (total >= ac) {
    const dmgDice = rollDamageFormula('1d6');
    target.currentHealth -= dmgDice.total;
    return { success: true, message: `✋ ${actor.name} Stand Stills ${target.name}! ${dmgDice.total} damage. Target's move action is disrupted (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
  }
  return { success: false, message: `${actor.name}'s Stand Still misses ${target.name} (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
}

