export function resolveDragonRoar(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const enemies = gameState.creatures.filter(c => c.type !== 'player' && ctx.calculateDistance(actor.positions, c.positions) <= 15);
  let frightened = 0;
  for (const e of enemies) {
    const roll = rollD20();
    const dc = ctx.getWillDC(e);
    const willBonus = ctx.getSkillBonus(e, 'will');
    const total = roll + willBonus;
    if (total < dc) {
      e.conditions = e.conditions || [];
      e.conditions.push({ name: 'Frightened', duration: 1, value: 1, source: 'Dragon Roar' });
      frightened++;
    }
  }
  return { success: true, message: `🐉 ${actor.name} unleashes Dragon Roar! ${frightened}/${enemies.length} enemies within 15 ft frightened 1 (req: Dragon Stance). Immune for 1 min on save.` };
}

