export function resolveOverwhelmingBreath(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const enemies = gameState.creatures.filter(c => c.type !== 'player' && ctx.calculateDistance(actor.positions, c.positions) <= 30);
  let totalDmg = 0;
  const dmgDice = rollDamageFormula('3d6');
  for (const e of enemies) {
    const saveRoll = rollD20();
    const dc = 10 + Math.floor(actor.level * 1.5);
    const saveBonus = ctx.getSkillBonus(e, 'reflex');
    const saveTotal = saveRoll + saveBonus;
    const degree = getDegreeOfSuccess(saveRoll, saveTotal, dc);
    let dmg = dmgDice.total;
    if (degree === 'critical-success') dmg = 0;
    else if (degree === 'success') dmg = Math.floor(dmg / 2);
    else if (degree === 'critical-failure') dmg = dmg * 2;
    e.currentHealth -= dmg;
    totalDmg += dmg;
  }
  return { success: true, message: `🌬️ ${actor.name} uses Overwhelming Breath! 30-ft cone/60-ft line: ${dmgDice.total} base damage (Reflex halves). ${enemies.length} enemies hit for ${totalDmg} total.` };
}

