export function resolveFlingingBlow(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 5) return { success: false, message: `${target.name} is out of melee range.` };
  const atkBonus = calculateAttackBonus(actor);
  const roll = rollD20();
  const ac = calculateAC(target);
  const total = roll + atkBonus;
  if (total >= ac) {
    const dmgDice = rollDamageFormula('2d6');
    target.currentHealth -= dmgDice.total;
    const fortRoll = rollD20();
    const fortDC = 10 + Math.floor(actor.level * 1.5);
    const fortBonus = ctx.getSkillBonus(target, 'fortitude');
    const fortTotal = fortRoll + fortBonus;
    if (fortTotal < fortDC) {
      target.conditions = target.conditions || [];
      target.conditions.push({ name: 'Prone', duration: 1, source: 'Flinging Blow' });
      return { success: true, message: `🥊 ${actor.name} Flinging Blows ${target.name}! ${dmgDice.total} damage + pushed 10 ft + prone (Fort failed: ${fortRoll}+${fortBonus}=${fortTotal} vs DC ${fortDC}) (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
    }
    return { success: true, message: `🥊 ${actor.name} Flinging Blows ${target.name}! ${dmgDice.total} damage (target saved vs push: ${fortRoll}+${fortBonus}=${fortTotal} vs DC ${fortDC}) (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
  }
  return { success: false, message: `${actor.name}'s Flinging Blow misses ${target.name} (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
}

