export function resolveSwiftRiver(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const removable = (actor.conditions || []).find(c => c.name === 'Immobilized' || c.name === 'Slowed' || c.name === 'Speed Penalty');
  if (removable) {
    actor.conditions = (actor.conditions || []).filter(c => c !== removable);
    return { success: true, message: `🌊 ${actor.name} uses Swift River! Removed ${removable.name}. Free action at end of turn.` };
  }
  return { success: true, message: `🌊 ${actor.name} uses Swift River! End one Speed penalty, immobilized, or slowed condition (none found to remove).` };
}

export function resolveTriangleShot(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  let hits = 0;
  let totalDmg = 0;
  for (let i = 0; i < 3; i++) {
    const atkBonus = calculateAttackBonus(actor) - 2;
    const roll = rollD20();
    const ac = calculateAC(target);
    const total = roll + atkBonus;
    if (total >= ac) {
      const dmgDice = rollDamageFormula('1d8');
      totalDmg += dmgDice.total;
      hits++;
    }
  }
  target.currentHealth -= totalDmg;
  const bleedMsg = hits === 3 ? ' + 3d6 persistent bleed!' : '';
  if (hits === 3) {
    const bleed = rollDamageFormula('3d6');
    target.conditions = target.conditions || [];
    target.conditions.push({ name: 'Persistent Bleed', duration: 3, value: bleed.total, source: 'Triangle Shot' });
  }
  return { success: true, message: `🏹 ${actor.name} Triangle Shots ${target.name}! ${hits}/3 hits for ${totalDmg} damage${bleedMsg} (req: Monastic Archer Stance + bow, Stunning Blows applies).` };
}

