export function resolveBlastLock(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const atkBonus = calculateAttackBonus(actor);
  const roll = rollD20();
  const dc = 10 + Math.floor(actor.level * 1.5);
  const total = roll + atkBonus;
  if (total >= dc) {
    return { success: true, message: `🔓 ${actor.name} Blast Locks! Lock opened (attack vs Pick Lock DC). (${roll}+${atkBonus}=${total} vs DC ${dc}).` };
  }
  return { success: false, message: `${actor.name}'s Blast Lock fails! Future attempts take –2 penalty (${roll}+${atkBonus}=${total} vs DC ${dc}).` };
}

export function resolveCoverFire(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const atkBonus = calculateAttackBonus(actor);
  const roll = rollD20();
  const ac = calculateAC(target);
  const total = roll + atkBonus;
  if (total >= ac) {
    target.conditions = target.conditions || [];
    target.conditions.push({ name: 'Ranged Penalty', duration: 1, value: -2, source: 'Cover Fire' });
    const dmgDice = rollDamageFormula('1d8');
    target.currentHealth -= dmgDice.total;
    return { success: true, message: `🔫 ${actor.name} Cover Fires ${target.name}! ${dmgDice.total} damage. Target didn't duck: +1 to hit (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
  }
  return { success: false, message: `${actor.name}'s Cover Fire misses ${target.name}. Target –2 ranged attacks if ducked (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
}

