export function resolveRiskyReload(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const strikeResult = ctx.resolveStrike(actor, gameState, target.id);
  return { success: true, message: `🎲 ${actor.name} Risky Reloads and fires at ${target.name}! Reload + Strike. Failure = misfire. ${strikeResult?.message || ''}` };
}

export function resolveWarningShot(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const intimidation = ctx.getSkillBonus(actor, 'intimidation');
  const roll = rollD20();
  const dc = ctx.getWillDC(target);
  const total = roll + intimidation;
  if (total >= dc) {
    target.conditions = target.conditions || [];
    target.conditions.push({ name: 'Frightened', duration: 1, value: 1, source: 'Warning Shot' });
    return { success: true, message: `💥 ${actor.name} fires a Warning Shot at ${target.name}! Frightened 1. Demoralize at firearm range, no language penalty (${roll}+${intimidation}=${total} vs DC ${dc}).` };
  }
  return { success: false, message: `${actor.name}'s Warning Shot doesn't faze ${target.name} (${roll}+${intimidation}=${total} vs DC ${dc}).` };
}

