export function resolveAlchemicalShot(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const atkBonus = calculateAttackBonus(actor);
  const roll = rollD20();
  const ac = calculateAC(target);
  const total = roll + atkBonus;
  if (total >= ac) {
    const dmgDice = rollDamageFormula('1d8');
    const persistDmg = rollDamageFormula('1d6');
    target.currentHealth -= dmgDice.total;
    target.conditions = target.conditions || [];
    target.conditions.push({ name: 'Persistent Fire', duration: 3, value: persistDmg.total, source: 'Alchemical Shot' });
    return { success: true, message: `🧪 ${actor.name} fires Alchemical Shot at ${target.name}! ${dmgDice.total} bomb-type damage + ${persistDmg.total} persistent (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
  }
  return { success: false, message: `${actor.name}'s Alchemical Shot misses ${target.name}! ${actor.name} takes 1d6 self-damage + misfire (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
}

export function resolveBlackPowderBoost(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  return { success: true, message: `💨 ${actor.name} uses Black Powder Boost! Leap +10 ft by firing weapon. 2 actions: High/Long Jump +10 ft.` };
}

export function resolveInstantBackup(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  return { success: true, message: `🔄 ${actor.name} uses Instant Backup! Reaction on misfire: Release misfired weapon + draw a different weapon.` };
}

export function resolveOstentatiousReload(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const performance = ctx.getSkillBonus(actor, 'performance');
  const roll = rollD20();
  const dc = 10 + Math.floor(actor.level * 1.5) - 2;
  const total = roll + performance;
  if (total >= dc + 10) {
    return { success: true, message: `🎪 ${actor.name} Ostentatiously Reloads! Crit: reload BOTH firearms! (${roll}+${performance}=${total} vs DC ${dc}).` };
  } else if (total >= dc) {
    return { success: true, message: `🎪 ${actor.name} Ostentatiously Reloads! Success: reload one firearm (${roll}+${performance}=${total} vs DC ${dc}).` };
  }
  return { success: false, message: `${actor.name}'s Ostentatious Reload fails! Drop firearm + ammo (${roll}+${performance}=${total} vs DC ${dc}).` };
}

export function resolvePairedShots(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  let hits = 0;
  let totalDmg = 0;
  for (let i = 0; i < 2; i++) {
    const atkBonus = calculateAttackBonus(actor);
    const roll = rollD20();
    const ac = calculateAC(target);
    const total = roll + atkBonus;
    if (total >= ac) {
      const dmgDice = rollDamageFormula('1d8');
      totalDmg += dmgDice.total;
      hits++;
    }
  }
  target.currentHealth -= totalDmg;
  return { success: true, message: `🔫🔫 ${actor.name} fires Paired Shots at ${target.name}! ${hits}/2 hits for ${totalDmg} combined damage. Counts as 2 attacks for MAP.` };
}

export function resolveGunslingerRunningReload(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  return { success: true, message: `🏃 ${actor.name} uses Running Reload! Stride/Step/Sneak then reload in 1 action.` };
}

