export function resolveCauterize(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const allies = gameState.creatures.filter(c => c.type === 'player');
  const bleeder = allies.find(c => (c.conditions || []).some(cond => cond.name.toLowerCase().includes('bleed')));
  if (bleeder) {
    bleeder.conditions = (bleeder.conditions || []).filter(c => !c.name.toLowerCase().includes('bleed'));
    return { success: true, message: `🔥 ${actor.name} Cauterizes ${bleeder.name}! Stopped persistent bleed with heated barrel (flat check DC 10).` };
  }
  return { success: true, message: `🔥 ${actor.name} uses Cauterize! Strike + press barrel to wounds. Immediate flat check to end bleed (reduced DC).` };
}

