export function resolvePhalanxBreaker(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const atkBonus = calculateAttackBonus(actor);
  const roll = rollD20();
  const ac = calculateAC(target);
  const total = roll + atkBonus;
  if (total >= ac) {
    const dmgDice = rollDamageFormula('2d8');
    target.currentHealth -= dmgDice.total;
    const pushDist = total >= ac + 10 ? 20 : 10;
    return { success: true, message: `💥 ${actor.name} Phalanx Breaks ${target.name}! ${dmgDice.total} damage + pushed ${pushDist} ft back. Obstacle collision: ${Math.floor(actor.level / 2)} B damage (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
  }
  return { success: false, message: `${actor.name}'s Phalanx Breaker misses ${target.name} (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
}

export function resolvePistolerosChallenge(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 30) return { success: false, message: `${target.name} is beyond 30 ft for challenge.` };
  const skill = Math.max(ctx.getSkillBonus(actor, 'deception'), ctx.getSkillBonus(actor, 'intimidation'));
  const roll = rollD20();
  const dc = ctx.getWillDC(target);
  const total = roll + skill;
  if (total >= dc) {
    const bonus = actor.level >= 19 ? 4 : actor.level >= 15 ? 3 : 2;
    return { success: true, message: `🤠 ${actor.name} challenges ${target.name}! Both gain +${bonus} status to damage vs each other until one falls/flees (${roll}+${skill}=${total} vs DC ${dc}).` };
  }
  return { success: false, message: `${actor.name}'s challenge to ${target.name} falls flat (${roll}+${skill}=${total} vs DC ${dc}).` };
}

export function resolveScatterBlast(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const atkBonus = calculateAttackBonus(actor);
  const roll = rollD20();
  const ac = calculateAC(target);
  const total = roll + atkBonus;
  if (total >= ac) {
    const dmgDice = rollDamageFormula('2d8');
    target.currentHealth -= dmgDice.total;
    return { success: true, message: `💣 ${actor.name} Scatter Blasts ${target.name}! ${dmgDice.total} damage. +20 ft range + scatter radius. Failure = misfire, crit fail = explode (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
  }
  return { success: false, message: `${actor.name}'s Scatter Blast misses ${target.name} — weapon misfires! (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
}

