    return { success: true, message: `🎯 ${actor.name} Sniper's Aims ${target.name}! ${dmgDice.total} damage (+2 circumstance, ignore concealment, req: Sniper) (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
