export function resolveTriggerbrandSalvo(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 5) return { success: false, message: `${target.name} is out of melee range.` };
  let totalDmg = 0;
  let hits = 0;
  const atkBonus = calculateAttackBonus(actor);
  const roll1 = rollD20();
  const ac = calculateAC(target);
  if (roll1 + atkBonus >= ac) {
    const d = rollDamageFormula('1d8');
    totalDmg += d.total;
    hits++;
    const roll2 = rollD20();
    if (roll2 + atkBonus + 2 >= ac) {
      const d2 = rollDamageFormula('1d8');
      totalDmg += d2.total;
      hits++;
    }
  }
  target.currentHealth -= totalDmg;
  return { success: true, message: `⚔️🔫 ${actor.name} Triggerbrand Salvos ${target.name}! ${hits}/2 hits for ${totalDmg} damage. Melee Strike → ranged Strike (+2 bonus, req: combination weapon).` };
}

