export function resolveBulletSplit(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  if (targets.length < 2) return { success: false, message: 'Need 2 adjacent enemies for Bullet Split.' };
  let totalDmg = 0;
  let hits = 0;
  for (let i = 0; i < 2 && i < targets.length; i++) {
    const t = targets[i];
    const atkBonus = calculateAttackBonus(actor) - 2;
    const roll = rollD20();
    const ac = calculateAC(t);
    const total = roll + atkBonus;
    if (total >= ac) {
      const dmgDice = rollDamageFormula('1d8');
      t.currentHealth -= dmgDice.total;
      totalDmg += dmgDice.total;
      hits++;
    }
  }
  return { success: true, message: `🔫✂️ ${actor.name} Bullet Splits! ${hits}/2 hits vs 2 adjacent targets for ${totalDmg} total damage (–2 each, counts as 1 for MAP).` };
}

