export function resolveReboundingAssault(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  let hits = 0;
  let totalDmg = 0;
  for (let i = 0; i < 2; i++) {
    const atkBonus = calculateAttackBonus(actor);
    const roll = rollD20();
    const ac = calculateAC(target);
    if (roll + atkBonus >= ac) {
      const dmgDice = rollDamageFormula('1d8');
      totalDmg += dmgDice.total;
      hits++;
    }
  }
  if (hits === 2) {
    const precision = rollDamageFormula('1d6');
    totalDmg += precision.total;
    target.currentHealth -= totalDmg;
    return { success: true, message: `🔄 ${actor.name} Rebounding Assaults ${target.name}! Both hit: ${totalDmg} combined damage (incl ${precision.total} precision). Weapon rebounds to hand.` };
  }
  target.currentHealth -= totalDmg;
  return { success: true, message: `🔄 ${actor.name} Rebounding Assaults ${target.name}! ${hits}/2 hits for ${totalDmg} damage. Weapon stays in target's space.` };
}

