export function resolveBloodInTheAir(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const atkBonus = calculateAttackBonus(actor);
  const roll = rollD20();
  const ac = calculateAC(target);
  const total = roll + atkBonus;
  if (total >= ac) {
    const dmgDice = rollDamageFormula('2d8');
    target.currentHealth -= dmgDice.total;
    return { success: true, message: `🩸 ${actor.name} Blood in the Air vs ${target.name}! ${dmgDice.total} damage. Ignores concealment, reduces hidden DC to 5 (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
  }
  return { success: false, message: `${actor.name}'s Blood in the Air misses ${target.name} (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
}

export function resolveDeadeye(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  actor.conditions = actor.conditions || [];
  actor.conditions.push({ name: 'See Invisible', duration: 1, source: 'Deadeye' });
  return { success: true, message: `👁️ ${actor.name} uses Deadeye! Until next turn: see invisible creatures as concealed silhouettes (air/ground disturbances).` };
}

export function resolveFleshWound(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const atkBonus = calculateAttackBonus(actor);
  const roll = rollD20();
  const ac = calculateAC(target);
  const total = roll + atkBonus;
  if (total >= ac) {
    const dmgDice = rollDamageFormula('2d8');
    target.currentHealth -= dmgDice.total;
    return { success: true, message: `🩹 ${actor.name} Flesh Wounds ${target.name}! ${dmgDice.total} damage (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
  }
  if (total >= ac - 10) {
    const minDmg = rollDamageFormula('1d8');
    target.currentHealth -= minDmg.total;
    return { success: true, message: `🩹 ${actor.name} grazes ${target.name} with Flesh Wound! ${minDmg.total} damage on failure (1 die + weapon spec only) (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
  }
  return { success: false, message: `${actor.name}'s Flesh Wound critically misses ${target.name} (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
}

export function resolveRicochetShot(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const atkBonus = calculateAttackBonus(actor);
  const roll = rollD20();
  const ac = calculateAC(target);
  const total = roll + atkBonus;
  if (total >= ac) {
    const dmgDice = rollDamageFormula('1d8');
    target.currentHealth -= dmgDice.total;
    return { success: true, message: `🔁 ${actor.name} Ricochet Shots ${target.name} off a surface! ${dmgDice.total} damage. Determine cover from ricochet point (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
  }
  return { success: false, message: `${actor.name}'s Ricochet Shot misses ${target.name} (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
}

export function resolveShatteringShot(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const enemies = gameState.creatures.filter(c => c.type !== 'player' && ctx.calculateDistance(actor.positions, c.positions) <= 15);
  const dmgDice = rollDamageFormula('2d6');
  let totalDmg = 0;
  for (const e of enemies) {
    const saveResult = ctx.rollSave(e, 'reflex', 10 + Math.floor(actor.level * 1.5));
    let dmg = dmgDice.total;
    if (saveResult.result === 'criticalSuccess') dmg = 0;
    else if (saveResult.result === 'success') dmg = Math.floor(dmg / 2);
    else if (saveResult.result === 'criticalFailure') dmg = dmg * 2;
    e.currentHealth -= dmg;
    totalDmg += dmg;
  }
  return { success: true, message: `💣 ${actor.name} Shattering Shots! Bomb + bullet in 15-ft burst: ${dmgDice.total} base bomb damage vs ${enemies.length} enemies (Reflex saves). ${totalDmg} total dealt.` };
}

