export function resolveBlastTackle(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 5) return { success: false, message: `${target.name} is out of melee range for grapple.` };
  const athletics = ctx.getSkillBonus(actor, 'athletics');
  const roll = rollD20();
  const dc = ctx.getFortitudeDC(target);
  const total = roll + athletics;
  if (total >= dc) {
    const dmgDice = rollDamageFormula('2d8');
    const precision = rollDamageFormula('3d6');
    target.currentHealth -= dmgDice.total + precision.total;
    target.conditions = target.conditions || [];
    target.conditions.push({ name: 'Grabbed', duration: 1, source: 'Blast Tackle' });
    return { success: true, message: `🤼💥 ${actor.name} Blast Tackles ${target.name}! Grapple + ${dmgDice.total}+${precision.total} damage (incl 3d6 precision). Target grabbed (${roll}+${athletics}=${total} vs DC ${dc}).` };
  }
  return { success: false, message: `${actor.name}'s Blast Tackle grapple fails vs ${target.name} (${roll}+${athletics}=${total} vs DC ${dc}).` };
}

