export function resolveDanceOfThunder(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  let hits = 0;
  let totalDmg = 0;
  for (let round = 0; round < 3; round++) {
    const atkBonus = calculateAttackBonus(actor);
    const roll = rollD20();
    const ac = calculateAC(target);
    const total = roll + atkBonus;
    if (total >= ac) {
      const dmgDice = rollDamageFormula('2d8');
      totalDmg += dmgDice.total;
      hits++;
    } else {
      break;
    }
  }
  target.currentHealth -= totalDmg;
  actor.conditions = actor.conditions || [];
  actor.conditions.push({ name: 'Fatigued', duration: 10, source: 'Dance of Thunder' });
  return { success: true, message: `⚡🩰 ${actor.name} dances the Dance of Thunder! ${hits}/3 rounds of Step + Strike + Reload. ${totalDmg} total damage. Now fatigued (1 min). (1/min, 3 actions).` };
}

export function resolveDisruptiveBlur(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  return { success: true, message: `🌀 ${actor.name} has Disruptive Blur! After firearm/crossbow Strike: no reactions triggered by your movement for rest of turn (req: Drifter).` };
}

export function resolveHeadshot(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const atkBonus = calculateAttackBonus(actor);
  const roll = rollD20();
  const ac = calculateAC(target);
  const total = roll + atkBonus;
  if (total >= ac + 10) {
    const fortRoll = rollD20();
    const fortBonus = ctx.getSkillBonus(target, 'fortitude');
    const fortDC = 10 + Math.floor(actor.level * 1.5);
    const fortTotal = fortRoll + fortBonus;
    if (fortTotal < fortDC) {
      target.currentHealth = 0;
      initDying(target);
      return { success: true, message: `💀 ${actor.name} HEADSHOTS ${target.name}! INSTANT KILL (Fort failed: ${fortRoll}+${fortBonus}=${fortTotal} vs DC ${fortDC}). This is a death/incapacitation effect (req: Sniper, crit hit).` };
    }
    const dmgDice = rollDamageFormula('4d8');
    target.currentHealth -= dmgDice.total;
    return { success: true, message: `🎯 ${actor.name} crits ${target.name} with Headshot! ${dmgDice.total} crit damage but survived Fort save (${fortRoll}+${fortBonus}=${fortTotal} vs DC ${fortDC}).` };
  }
  if (total >= ac) {
    const dmgDice = rollDamageFormula('2d8');
    target.currentHealth -= dmgDice.total;
    return { success: true, message: `🎯 ${actor.name} Headshots ${target.name}! ${dmgDice.total} damage (hit but not crit — no death effect) (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
  }
  return { success: false, message: `${actor.name}'s Headshot misses ${target.name} (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
}

export function resolveShowstopper(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const enemies = gameState.creatures.filter(c => c.type !== 'player' && ctx.calculateDistance(actor.positions, c.positions) <= 60);
  const deception = ctx.getSkillBonus(actor, 'deception');
  const roll = rollD20();
  let feinted = 0;
  for (const e of enemies) {
    const dc = ctx.getPerceptionDC(e);
    if (roll + deception >= dc) {
      e.conditions = e.conditions || [];
      e.conditions.push({ name: 'Off-Guard', duration: 1, source: 'Showstopper' });
      feinted++;
    }
  }
  return { success: true, message: `🎪 ${actor.name} Showstops! Pistol Twirl Feint vs ALL ${enemies.length} visible enemies in range: ${feinted} off-guard! (${roll}+${deception}, req: Master Deception).` };
}

export function resolveTriggerbrandBlitz(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  let hits = 0;
  let totalDmg = 0;
  const numTargets = Math.min(3, targets.length);
  for (let i = 0; i < numTargets; i++) {
    const t = targets[i];
    const atkBonus = calculateAttackBonus(actor);
    const roll = rollD20();
    const ac = calculateAC(t);
    if (roll + atkBonus >= ac) {
      const dmgDice = rollDamageFormula('1d8');
      t.currentHealth -= dmgDice.total;
      totalDmg += dmgDice.total;
      hits++;
    }
  }
  actor.conditions = actor.conditions || [];
  actor.conditions.push({ name: 'Fatigued', duration: 10, source: 'Triggerbrand Blitz' });
  return { success: true, message: `⚔️🔫💨 ${actor.name} Triggerbrand Blitzes! Stride + ${hits}/${numTargets} Strikes vs different targets for ${totalDmg} damage. Now fatigued (1 min).` };
}

