export function resolveFinalShot(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  const targets = gameState.creatures.filter(c => c.type !== 'player');
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : targets[0];
  if (!target) return { success: false, message: 'No valid target.' };
  const atkBonus = calculateAttackBonus(actor);
  const roll = rollD20();
  const ac = calculateAC(target);
  const total = roll + atkBonus;
  if (total >= ac) {
    const dmgDice = rollDamageFormula('4d8');
    const doubleDmg = dmgDice.total * 2;
    target.currentHealth -= doubleDmg;
    actor.conditions = actor.conditions || [];
    actor.conditions.push({ name: 'Off-Guard', duration: 1, source: 'Final Shot' });
    actor.conditions.push({ name: 'Stunned', duration: 1, value: 1, source: 'Final Shot' });
    return { success: true, message: `💥💥💥 ${actor.name} fires a FINAL SHOT at ${target.name}! Success → crit: ${doubleDmg} damage! Actor off-guard + stunned 1 (triple charge, 3 actions) (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
  }
  actor.conditions = actor.conditions || [];
  actor.conditions.push({ name: 'Off-Guard', duration: 1, source: 'Final Shot' });
  actor.conditions.push({ name: 'Stunned', duration: 1, value: 1, source: 'Final Shot' });
  return { success: false, message: `${actor.name}'s Final Shot misses ${target.name} — weapon misfires! Off-guard + stunned 1 (${roll}+${atkBonus}=${total} vs AC ${ac}).` };
}

