export function resolveAlchemy(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // Core class feature: grants trained in Crafting, Quick Alchemy, formulas
  return { success: true, message: `⚗️ ${actor.name}'s Alchemy: trained in Crafting, can use Quick Alchemy to create alchemical items during encounters using Infused Reagents.` };
}

export function resolveVersatileVials(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  // Create and throw a versatile vial — acid damage scaling by level
  if (!targetId) {
    const vialCount = 2 + Math.floor(actor.level / 2);
    return { success: true, message: `⚗️ ${actor.name} prepares ${vialCount} Versatile Vials for the day.` };
  }
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 4) return { success: false, message: 'Target must be within 20 feet.' };
  // Damage scales: 1d6 (L1), 2d6 (L4), 3d6 (L12), 4d6 (L18)
  const dice = actor.level >= 18 ? 4 : actor.level >= 12 ? 3 : actor.level >= 4 ? 2 : 1;
  const dmgRoll = rollDamageFormula(`${dice}d6`);
  const splashDmg = Math.max(1, dice);
  const totalDmg = dmgRoll.total;
  if (target.currentHealth > 0) {
    target.currentHealth = Math.max(0, target.currentHealth - totalDmg);
    if (target.currentHealth <= 0) initDying(target);
  }
  return { success: true, message: `⚗️💥 ${actor.name} hurls a Versatile Vial at ${target.name} — ${totalDmg} acid damage (${dice}d6) + ${splashDmg} splash! (HP: ${target.currentHealth}/${target.maxHealth})` };
}

