// Level 1

export function resolveAlchemicalAssessment(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  // 1-action Crafting check to ID weaknesses/resistances
  if (!targetId) return { success: false, message: 'Alchemical Assessment requires a target.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 12) return { success: false, message: 'Target must be within 60 feet.' };
  const craftingBonus = ctx.getSkillBonus(actor, 'crafting');
  const roll = rollD20();
  const total = roll + craftingBonus;
  const dc = 15 + Math.floor(target.level * 1.5);
  const degree = getDegreeOfSuccess(total, dc, roll);
  if (degree === 'critical-success') {
    return { success: true, message: `⚗️🔍 Alchemical Assessment (Critical)! ${actor.name} identifies ${target.name}'s weaknesses, resistances, immunities, and lowest save (roll: ${total} vs DC ${dc}).` };
  } else if (degree === 'success') {
    return { success: true, message: `⚗️🔍 Alchemical Assessment! ${actor.name} identifies ${target.name}'s weaknesses and resistances (roll: ${total} vs DC ${dc}).` };
  }
  return { success: true, message: `⚗️❌ Alchemical Assessment failed — ${actor.name} couldn't identify ${target.name}'s properties (roll: ${total} vs DC ${dc}).` };
}

export function resolveAlchemicalFamiliar(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const result = spawnFamiliar(actor, gameState, 'Alchemical Homunculus');
  if (result) {
    return { success: true, message: `⚗️🐾 ${actor.name} creates an Alchemical Familiar — a homunculus that can deliver elixirs and bombs!` };
  }
  return { success: true, message: `⚗️🐾 ${actor.name}'s Alchemical Familiar is already active.` };
}

export function resolveBlowgunPoisoner(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  return { success: true, message: `⚗️🎯 ${actor.name}'s Blowgun Poisoner: trained with blowguns, apply poisons to darts as single Interact action. Blowgun damage die increases to d8 with poisons.` };
}

export function resolveFarLobber(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  return { success: true, message: `⚗️📏 ${actor.name}'s Far Lobber: bomb range increment increases by 10 feet (from 20 to 30 feet).` };
}

export function resolveQuickBomber(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  // 1-action: draw + Strike with bomb
  if (!targetId) return { success: false, message: 'Quick Bomber requires a target — draws and throws a bomb in 1 action.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  const range = ctx.hasFeat(actor, 'far lobber') ? 6 : 4;
  if (dist > range) return { success: false, message: `Target must be within ${range * 5} feet.` };
  const strikeResult = ctx.resolveAttackAction(actor, gameState, targetId, undefined, { isVicious: false });
  if (!strikeResult.success) return strikeResult;
  strikeResult.message = `⚗️💣 Quick Bomber! ${actor.name} draws and throws in one motion!\n${strikeResult.message}`;
  return strikeResult;
}

export function resolveSoothingVials(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: true, message: `⚗️💚 ${actor.name}'s Soothing Vials: versatile vials grant temporary HP equal to half level when used on allies.` };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const tempHP = Math.max(1, Math.floor(actor.level / 2));
  target.temporaryHealth = Math.max(target.temporaryHealth || 0, tempHP);
  return { success: true, message: `⚗️💚 Soothing Vials! ${actor.name}'s vial grants ${target.name} ${tempHP} temporary HP.` };
}

// Level 2

export function resolveClottingElixirs(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: true, message: `⚗️🩹 ${actor.name}'s Clotting Elixirs: elixirs of life grant resistance to persistent bleed damage equal to the elixir's item level.` };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  if (target.conditions) {
    const bleedIdx = target.conditions.findIndex((c) => c.name === 'persistent-bleed' || c.name === 'bleed');
    if (bleedIdx >= 0) {
      target.conditions.splice(bleedIdx, 1);
      return { success: true, message: `⚗️🩹 Clotting Elixirs! ${actor.name}'s elixir stops ${target.name}'s bleeding!` };
    }
  }
  return { success: true, message: `⚗️🩹 Clotting Elixirs! ${actor.name}'s elixir grants ${target.name} resistance to bleed damage.` };
}

export function resolveImproviseAdmixture(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  return { success: true, message: `⚗️🧪 Improvise Admixture! ${actor.name} hastily mixes nearby materials to create 2 Versatile Vials from the environment.` };
}

export function resolvePerniciousPoison(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  // Additive: next bomb inflicts poison at +1 stage on failed save
  if (!targetId) return { success: true, message: `⚗️☠️ ${actor.name} prepares Pernicious Poison — next bomb inflicts poison at +1 stage on failed save.` };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  if (!target.conditions) target.conditions = [];
  target.conditions.push({ name: 'poisoned', duration: 3, value: 2, source: 'Pernicious Poison' });
  return { success: true, message: `⚗️☠️ Pernicious Poison! ${actor.name}'s poison is extra virulent — ${target.name} starts at stage 2 poison!` };
}

export function resolvePoisonResistance(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const resistance = Math.max(1, Math.floor(actor.level / 2));
  if (!actor.conditions) actor.conditions = [];
  const existing = actor.conditions.find((c) => c.name === 'poison-resistance');
  if (!existing) {
    actor.conditions.push({ name: 'poison-resistance', duration: 'permanent', value: resistance, source: 'Poison Resistance' });
  }
  return { success: true, message: `⚗️🛡️ Poison Resistance! ${actor.name} has poison resistance ${resistance} (half level).${actor.level >= 12 ? ' Also gains +1 status bonus to poison saves.' : ''}` };
}

export function resolveRevivifyingMutagen(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // When mutagen ends, heal
  const healAmount = rollDamageFormula('2d6').total + actor.level;
  actor.currentHealth = Math.min(actor.maxHealth, actor.currentHealth + healAmount);
  if (actor.conditions) {
    actor.conditions = actor.conditions.filter((c) => !c.source?.includes('mutagen'));
  }
  return { success: true, message: `⚗️💚 Revivifying Mutagen! ${actor.name}'s mutagen ends and their body rejuvenates — healed ${healAmount} HP! (HP: ${actor.currentHealth}/${actor.maxHealth})` };
}

export function resolveSmokeBomb(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  // Additive: bomb creates concealment cloud
  if (!targetId) return { success: true, message: `⚗️💨 ${actor.name} adds Smoke Bomb — next bomb creates a 10-foot smoke cloud granting concealment for 1 minute.` };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const nearbyCreatures = gameState.creatures.filter(c => ctx.calculateDistance(target.positions, c.positions) <= 2);
  nearbyCreatures.forEach(c => {
    if (!c.conditions) c.conditions = [];
    c.conditions.push({ name: 'concealed', duration: 3, source: 'Smoke Bomb' });
  });
  return { success: true, message: `⚗️💨 Smoke Bomb! ${actor.name}'s bomb explodes into a smoke cloud — ${nearbyCreatures.length} creatures concealed in 10-ft radius!` };
}

