export function resolveCalculatedSplash(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const intMod = Math.max(1, Math.floor((actor.level + 4) / 4));
  return { success: true, message: `⚗️🎯 ${actor.name}'s Calculated Splash: splash damage from bombs increases by Intelligence modifier (+${intMod}).` };
}

