  if (!targetId) return { success: true, message: `⚗️💫 ${actor.name} adds Debilitating Bomb — next bomb applies: dazzled (fire), deafened (sonic), off-guard (acid), or -5 ft Speed (cold).` };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  if (!target.conditions) target.conditions = [];
  target.conditions.push({ name: 'off-guard', duration: 2, source: 'Debilitating Bomb' });
  return { success: true, message: `⚗️💫 Debilitating Bomb! ${actor.name}'s bomb debilitates ${target.name} — off-guard until end of next turn!` };
