export function resolveImprovedInvigoratingElixir(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: true, message: `⚗️✨ ${actor.name}'s Improved Invigorating Elixir: elixirs now reduce conditions by 2 instead of 1, and also reduce drained and sickened.` };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const removable = ['clumsy', 'enfeebled', 'stupefied', 'drained', 'sickened'];
  if (target.conditions) {
    for (const cName of removable) {
      const cond = target.conditions.find((c) => c.name === cName);
      if (cond && cond.value) {
        cond.value = Math.max(0, cond.value - 2);
        if (cond.value <= 0) target.conditions = target.conditions.filter((c) => c.name !== cName);
        return { success: true, message: `⚗️✨ Improved Invigorating Elixir! ${target.name}'s ${cName} reduced by 2!` };
      }
    }
  }
  return { success: true, message: `⚗️✨ Improved Invigorating Elixir — ${target.name} has no conditions to reduce.` };
}

