export function resolveGreaterMercifulElixir(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: false, message: 'Greater Merciful Elixir requires a target.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const removable = ['frightened', 'sickened', 'persistent-damage', 'persistent-bleed', 'bleed', 'paralyzed', 'petrified', 'stunned', 'slowed'];
  let removed: string[] = [];
  if (target.conditions) {
    for (const cName of removable) {
      const idx = target.conditions.findIndex((c) => c.name === cName);
      if (idx >= 0) {
        removed.push(cName);
        target.conditions.splice(idx, 1);
      }
    }
  }
  return { success: true, message: removed.length > 0
    ? `⚗️💚✨ Greater Merciful Elixir! Removes ${removed.join(', ')} from ${target.name}!`
    : `⚗️💚✨ Greater Merciful Elixir! ${target.name} drinks (no conditions to remove).` };
}

export function resolveTrueDebilitatingBomb(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!targetId) return { success: true, message: `⚗️💫 ${actor.name}'s True Debilitating Bomb: ultimate conditions — blinded + stunned 1, off-guard + slowed 1, -15 ft Speed, deafened + persistent sonic.` };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  if (!target.conditions) target.conditions = [];
  target.conditions.push({ name: 'blinded', duration: 2, source: 'True Debilitating Bomb' });
  target.conditions.push({ name: 'stunned', duration: 1, value: 1, source: 'True Debilitating Bomb' });
  target.conditions.push({ name: 'off-guard', duration: 3, source: 'True Debilitating Bomb' });
  return { success: true, message: `⚗️💫👑 True Debilitating Bomb! ${target.name} is blinded, stunned 1, and off-guard!` };
}

// Level 16

export function resolveEternalElixir(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  return { success: true, message: `⚗️♾️ ${actor.name}'s Eternal Elixir: during daily preparations, create one elixir that never expires. Lasts until consumed or next daily prep.` };
}

export function resolveChemicalContagion(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  // Reaction: spread poison to adjacent creatures
  if (!targetId) return { success: false, message: 'Chemical Contagion requires a poisoned target.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const hasPoisonCond = target.conditions?.some((c) => c.name === 'poisoned' || c.source?.includes('Poison'));
  if (!hasPoisonCond) return { success: false, message: `${target.name} is not currently poisoned.` };
  const adjacent = gameState.creatures.filter(c =>
    c.id !== target.id && c.type !== 'player' && ctx.calculateDistance(target.positions, c.positions) <= 1
  );
  adjacent.forEach(adj => {
    if (!adj.conditions) adj.conditions = [];
    adj.conditions.push({ name: 'poisoned', duration: 3, value: 1, source: 'Chemical Contagion' });
  });
  return { success: true, message: `⚗️☠️💨 Chemical Contagion! ${actor.name}'s poison spreads from ${target.name} to ${adjacent.length} adjacent creatures!` };
}

// Level 18-20

export function resolveMegaBomb(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  // Additive: 30ft burst, max splash damage
  if (!targetId) return { success: true, message: `⚗️💣 ${actor.name} prepares Mega Bomb — next bomb becomes a 30-foot burst with maximum splash damage!` };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const inRadius = gameState.creatures.filter(c =>
    c.id !== actor.id && ctx.calculateDistance(target.positions, c.positions) <= 6
  );
  const dice = actor.level >= 18 ? 4 : actor.level >= 12 ? 3 : 2;
  const splashMax = dice * 6;
  let messages: string[] = [];
  inRadius.forEach(c => {
    const dmg = rollDamageFormula(`${dice}d6`).total + splashMax;
    const finalDmg = calculateFinalDamage(dmg, 'bludgeoning', c);
    c.currentHealth = Math.max(0, c.currentHealth - finalDmg.finalDamage);
    if (c.currentHealth <= 0) initDying(c);
    messages.push(`${c.name}: ${finalDmg.finalDamage} dmg (HP: ${c.currentHealth}/${c.maxHealth})`);
  });
  return { success: true, message: `⚗️💣💥 MEGA BOMB! ${actor.name}'s colossal bomb erupts in a 30-ft burst!\n${messages.join('\n')}` };
}

export function resolvePerfectMutagen(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // Remove mutagen drawbacks
  if (actor.conditions) {
    actor.conditions = actor.conditions.filter((c) =>
      !(c.source?.includes('mutagen') && (c.name === 'clumsy' || c.name === 'enfeebled' || c.name === 'stupefied'))
    );
  }
  return { success: true, message: `⚗️👑 Perfect Mutagen! ${actor.name} has perfected their mutagenic formula — all mutagen drawbacks removed while retaining full benefits!` };
}


