// Level 1

export function resolveApparitionSense(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // 1-action: detect spirits within 30 feet
  const spirits = gameState.creatures.filter(c => {
    if (ctx.calculateDistance(actor.positions, c.positions) > 6) return false;
    const specials = Array.isArray(c.specials) ? c.specials.join(' ').toLowerCase() : '';
    return specials.includes('spirit') || specials.includes('undead') || specials.includes('ethereal');
  });
  return { success: true, message: `👻🔍 Apparition Sense! ${actor.name} reaches out to the spirit world — detects ${spirits.length} spiritual presence${spirits.length !== 1 ? 's' : ''} within 30 feet.` };
}

export function resolveChannelersStance(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // Stance: reduce casting actions by 1 for vessel spells
  if (!actor.conditions) actor.conditions = [];
  const existing = actor.conditions.find((c) => c.name === 'channelers-stance');
  if (existing) return { success: true, message: `👻 ${actor.name} is already in Channeler's Stance.` };
  // Remove other stances
  actor.conditions = actor.conditions.filter((c) => !c.name?.includes('-stance'));
  actor.conditions.push({ name: 'channelers-stance', duration: 'permanent', source: "Channeler's Stance" });
  return { success: true, message: `👻🧘 Channeler's Stance! ${actor.name} enters a meditative state — vessel spells cost 1 fewer action to cast (minimum 1).` };
}

