export function resolveEnhancedFamiliar(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // Enhanced Familiar grants +2 familiar abilities per day
  if (!actor.familiar) return { success: false, message: `${actor.name} has no familiar to enhance.` };
  actor.familiar.abilitiesPerDay = Math.max(actor.familiar.abilitiesPerDay, 4);
  return { success: true, message: `👻 ${actor.name}'s familiar now has ${actor.familiar.abilitiesPerDay} abilities per day (Enhanced Familiar).` };
}

export function resolveGraspingSpirits(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  // Spellshape: +30ft range, pull 5ft
  if (!targetId) return { success: true, message: `👻🖐️ ${actor.name} shapes their spell with Grasping Spirits — range increases by 30 feet. On hit, target is pulled 5 feet toward ${actor.name}.` };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  // Pull target 5ft (1 square) closer
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 1) {
    const dx = actor.positions.x - target.positions.x;
    const dy = actor.positions.y - target.positions.y;
    const len = Math.sqrt(dx * dx + dy * dy);
    if (len > 0) {
      target.positions = {
        x: target.positions.x + Math.round(dx / len),
        y: target.positions.y + Math.round(dy / len)
      };
    }
  }
  return { success: true, message: `👻🖐️ Grasping Spirits! ${actor.name}'s spell pulls ${target.name} 5 feet closer!` };
}

