export function resolveRoaringHeart(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  // 2-action: charge + strike
  if (!targetId) return { success: false, message: 'Roaring Heart requires a melee target.' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  const speed = getEffectiveSpeed(actor);
  const maxCharge = Math.floor(speed / 5) * 2; // Double stride
  if (dist > maxCharge) return { success: false, message: `Target is too far for Roaring Heart charge (max ${maxCharge * 5} feet).` };
  // Move to adjacent
  if (dist > 1) {
    const dx = target.positions.x - actor.positions.x;
    const dy = target.positions.y - actor.positions.y;
    const len = Math.sqrt(dx * dx + dy * dy);
    actor.positions = {
      x: target.positions.x - Math.round(dx / len),
      y: target.positions.y - Math.round(dy / len)
    };
  }
  const strikeResult = ctx.resolveAttackAction(actor, gameState, targetId, undefined, { isVicious: false });
  if (!strikeResult.success) return strikeResult;
  return { success: true, message: `👻💨⚔️ Roaring Heart! ${actor.name} charges with spiritual fury!\n${strikeResult.message}` };
}

