// Level 18-20

export function resolveCycleOfSouls(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  return { success: true, message: `👻🔄 ${actor.name}'s Cycle of Souls: if ${actor.name} dies, their soul enters the cycle of reincarnation. After 24 hours, can return in a new body (retaining all abilities and memories).` };
}

export function resolveEchoingChannel(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  return { success: true, message: `👻📢 Echoing Channel! ${actor.name}'s next Heal or Harm spell is duplicated — cast it again as a free action on the same or different target.` };
}

export function resolveSpiritsSacrifice(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  // Reaction: prevent death
  if (!targetId) return { success: false, message: "Spirit's Sacrifice requires a dying ally." };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target) return { success: false, message: 'Target not found.' };
  const dist = ctx.calculateDistance(actor.positions, target.positions);
  if (dist > 6) return { success: false, message: 'Ally must be within 30 feet.' };
  // Prevent death - set to 1 HP
  if (target.currentHealth <= 0) {
    target.currentHealth = 1;
    if (target.conditions) {
      target.conditions = target.conditions.filter((c) => c.name !== 'dying' && c.name !== 'unconscious');
    }
  }
  // Cost: actor takes spirit damage
  const cost = Math.floor(actor.maxHealth / 4);
  actor.currentHealth = Math.max(0, actor.currentHealth - cost);
  if (actor.currentHealth <= 0) initDying(actor);
  return { success: true, message: `👻💀 Spirit's Sacrifice! ${actor.name}'s apparition shields ${target.name} from death! ${target.name} stabilizes at 1 HP. ${actor.name} takes ${cost} spirit damage. (${actor.name} HP: ${actor.currentHealth}/${actor.maxHealth})` };
}

export function resolveEternalGuide(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  return { success: true, message: `👻♾️ ${actor.name}'s Eternal Guide: if ${actor.name} dies, their apparitions sustain their spirit. Automatically resurrected at the start of the next day with full HP, no negative effects.` };
}

export function resolveTrueChannel(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // Free action: recover highest-level spell slot
  return { success: true, message: `👻👑 True Channel! ${actor.name} achieves perfect spiritual harmony — recovers their highest-level expended spell slot as a free action. Once per 10 minutes.` };
}


