export function resolveAnimalCompanion(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // If actor already has a companion, report it; otherwise spawn a default wolf
  const existing = getOwnerCompanions(actor.id, gameState);
  if (existing.length > 0) {
    return { success: true, message: `🌿 ${actor.name} already has an animal companion (${existing[0].name}). Use 'command-companion' to direct it.` };
  }
  return spawnCompanion(actor, 'wolf', gameState, 'young');
}

