export function resolveMatureAnimalCompanion(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const companions = getOwnerCompanions(actor.id, gameState);
  if (companions.length === 0) return { success: false, message: `${actor.name} has no animal companion to mature.` };
  const comp = companions[0];
  if (comp.maturity !== 'young') return { success: true, message: `🌿 ${comp.name} is already ${comp.maturity} maturity.` };
  return matureCompanion(comp.id, 'mature', gameState);
}

