export function resolveParagonCompanion(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const companions = getOwnerCompanions(actor.id, gameState);
  if (companions.length === 0) return { success: false, message: `${actor.name} has no companion to upgrade.` };
  const comp = companions[0];
  // Paragon is equivalent to savage maturity
  return matureCompanion(comp.id, 'savage', gameState);
}

