export function resolveMasterfulCompanion(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  const companions = getOwnerCompanions(actor.id, gameState);
  if (companions.length === 0) return { success: false, message: `${actor.name} has no companion to upgrade.` };
  const comp = companions[0];
  // Masterful = nimble maturity path
  return matureCompanion(comp.id, 'nimble', gameState);
}

