export function resolveFamiliar(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // If already has familiar, report; otherwise spawn one
  if (actor.familiar) {
    const existing = (gameState.companions || []).find(c => c.id === actor.familiar!.id);
    return { success: true, message: `🔮 ${actor.name} already has a familiar${existing ? ` (${existing.name})` : ''}. Use 'select-familiar-abilities' to assign daily abilities.` };
  }
  return spawnFamiliar(actor, gameState);
}

