export function resolveEidolon(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // Eidolon class feature — manifest the eidolon if not already active
  if (actor.eidolonId) {
    const existing = (gameState.companions || []).find(c => c.id === actor.eidolonId);
    if (existing && existing.manifested) {
      return { success: true, message: `🐉 ${actor.name}'s eidolon ${existing.name} is already manifested. Use 'command-eidolon' or 'act-together'.` };
    }
  }
  return manifestEidolon(actor, gameState);
}

