export function resolveEvolutionFeat(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // Apply an evolution to the eidolon — default to energy-heart
  if (!actor.eidolonId) return { success: false, message: `${actor.name} has no eidolon to evolve.` };
  return applyEvolution(actor, 'energy-heart', gameState);
}

