export function resolveInstantManifestation(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // Instant Manifestation: manifest eidolon as a free action
  const result = manifestEidolon(actor, gameState);
  if (result.success) {
    result.message = `🐉 ${actor.name} instantly manifests their eidolon! ` + (result.message || '');
  }
  return result;
}

