export function resolveMeldIntoEidolon(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!actor.eidolonId) return { success: false, message: `${actor.name} has no eidolon to meld into.` };
  const eidolon = (gameState.companions || []).find(c => c.id === actor.eidolonId);
  if (!eidolon || !eidolon.manifested) return { success: false, message: `Eidolon is not currently manifested.` };
  // Mark as melded — summoner vanishes, eidolon gains summoner’s senses
  (actor as any).meldedIntoEidolon = true;
  eidolon.canActIndependently = true;
  return { success: true, message: `🐉 ${actor.name} melds into their eidolon ${eidolon.name}! The eidolon gains the summoner's awareness.` };
}

export function resolveUnfetterEidolon(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!actor.eidolonId) return { success: false, message: `${actor.name} has no eidolon to unfetter.` };
  const eidolon = (gameState.companions || []).find(c => c.id === actor.eidolonId);
  if (!eidolon || !eidolon.manifested) return { success: false, message: `Eidolon is not manifested.` };
  eidolon.canActIndependently = true;
  return { success: true, message: `🐉 ${actor.name} unfetters their eidolon ${eidolon.name}! It can now act beyond 100 feet.` };
}

