export function resolveDefendSummoner(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!actor.eidolonId) return { success: true, message: `🐉 ${actor.name} uses Defend Summoner! (no eidolon present)` };
  const eidolon = (gameState.companions || []).find(c => c.id === actor.eidolonId);
  if (!eidolon || !eidolon.manifested) return { success: false, message: `Eidolon is not manifested to defend.` };
  // Grant +2 circumstance bonus to AC until start of next turn
  if (!eidolon.conditions) eidolon.conditions = [];
  eidolon.conditions.push({ name: 'defend-summoner', duration: 1, value: 2 });
  return { success: true, message: `🐉 ${eidolon.name} interposes to defend ${actor.name}! (+2 circumstance bonus to AC for 1 round)` };
}

