export function resolveBondCompanion(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  // Bond Companion — grants an animal companion (ancestry feat)
  const existing = getOwnerCompanions(actor.id, gameState);
  if (existing.length > 0) {
    return { success: true, message: `🧬 ${actor.name} already has a bonded companion (${existing[0].name}).` };
  }
  return spawnCompanion(actor, 'bird', gameState, 'young');
}

