export function resolveBattleMedicine(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Battle Medicine')) {
    return { success: false, message: `${actor.name} does not have Battle Medicine.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  // Default to self-heal if no target
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : actor;
  if (!target || target.currentHealth <= 0) {
    return { success: false, message: 'Target not found or is unconscious.', errorCode: 'TARGET_NOT_FOUND' };
  }

  // Check immunity — Battle Medicine can only be used once per target per day
  if (!target.conditions) target.conditions = [];
  const alreadyTreated = target.conditions.some(c => c.name === 'battle-medicine-immunity' && c.source === `bm-${actor.id}`);
  if (alreadyTreated) {
    return { success: false, message: `${target.name} has already been treated by ${actor.name}'s Battle Medicine today.`, errorCode: 'ALREADY_TREATED' };
  }

  const medicineBonus = ctx.getSkillBonus(actor, 'medicine');
  const dc = 15; // Trained DC for Treat Wounds
  const d20 = rollD20();
  let total = d20 + medicineBonus;
  let finalD20 = d20;
  let heroPointMessage: string | undefined;

  if (heroPointsSpent && heroPointsSpent > 0) {
    const spendResult = ctx.spendHeroPoints(actor, heroPointsSpent, { d20, bonus: medicineBonus, total, result: 'pending' });
    if (spendResult.success && spendResult.newRoll) {
      finalD20 = spendResult.newRoll.d20;
      total = spendResult.newRoll.total;
      heroPointMessage = spendResult.message;
    }
  }

  const result = getDegreeOfSuccess(finalD20, total, dc);
  let message = `⚕️ ${actor.name} uses Battle Medicine on ${target.name}!\n`;
  message += `Medicine: ${finalD20} + ${medicineBonus} = ${total} vs DC ${dc}\n`;
  message += `Result: **${result.toUpperCase()}**`;

  // Apply immunity regardless of result (1/day per target per healer)
  target.conditions.push({ name: 'battle-medicine-immunity', duration: 'permanent', value: 1, source: `bm-${actor.id}` });

  let healing = 0;
  if (result === 'critical-success') {
    healing = rollDamageFormula('4d8');
    target.currentHealth = Math.min(target.maxHealth, target.currentHealth + healing);
    message += `\n✨ Critical success! ${target.name} heals ${healing} HP! (HP: ${target.currentHealth}/${target.maxHealth})`;
  } else if (result === 'success') {
    healing = rollDamageFormula('2d8');
    target.currentHealth = Math.min(target.maxHealth, target.currentHealth + healing);
    message += `\n✅ ${target.name} heals ${healing} HP! (HP: ${target.currentHealth}/${target.maxHealth})`;
  } else if (result === 'critical-failure') {
    const damage = rollDamageFormula('1d8');
    target.currentHealth = Math.max(0, target.currentHealth - damage);
    message += `\n💥 Critical failure! ${target.name} takes ${damage} damage! (HP: ${target.currentHealth}/${target.maxHealth})`;
  } else {
    message += `\n❌ No effect.`;
  }

  if (heroPointMessage) message += `\n${heroPointMessage}`;
  return { success: true, message, details: { d20: finalD20, medicineBonus, total, dc, result, healing } };
}

export function resolveCatFall(ctx: FeatActionContext, actor: Creature, gameState: GameState): ActionResult {
  if (!ctx.hasFeat(actor, 'Cat Fall')) {
    return { success: false, message: `${actor.name} does not have Cat Fall.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  // Cat Fall: treat falls as shorter based on Acrobatics proficiency
  // Trained: treat as 10 ft less, Expert: 25 ft less, Master: 50 ft less, Legendary: always land on feet
  const acrobaticsBonus = ctx.getSkillBonus(actor, 'acrobatics');
  let reduction = 10; // trained
  if (acrobaticsBonus >= 20) reduction = 9999; // legendary — negate all
  else if (acrobaticsBonus >= 15) reduction = 50; // master
  else if (acrobaticsBonus >= 10) reduction = 25; // expert

  return { success: true, message: `🐱 ${actor.name}'s Cat Fall reduces effective fall distance by ${reduction} feet! (Acrobatics +${acrobaticsBonus})`, details: { fallReduction: reduction } };
}

