export function resolveFascinatingPerformance(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Fascinating Performance')) {
    return { success: false, message: `${actor.name} does not have Fascinating Performance.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target || target.currentHealth <= 0) {
    return { success: false, message: 'Target not found or is unconscious.', errorCode: 'TARGET_NOT_FOUND' };
  }

  const performanceBonus = ctx.getSkillBonus(actor, 'performance');
  const willDC = ctx.getWillDC(target);
  const d20 = rollD20();
  let total = d20 + performanceBonus;
  let finalD20 = d20;
  let heroPointMessage: string | undefined;

  if (heroPointsSpent && heroPointsSpent > 0) {
    const spendResult = ctx.spendHeroPoints(actor, heroPointsSpent, { d20, bonus: performanceBonus, total, result: 'pending' });
    if (spendResult.success && spendResult.newRoll) {
      finalD20 = spendResult.newRoll.d20;
      total = spendResult.newRoll.total;
      heroPointMessage = spendResult.message;
    }
  }

  const result = getDegreeOfSuccess(finalD20, total, willDC);
  let message = `🎭 ${actor.name} performs for ${target.name}!\n`;
  message += `Performance: ${finalD20} + ${performanceBonus} = ${total} vs Will DC ${willDC}\n`;
  message += `Result: **${result.toUpperCase()}**`;

  if (!target.conditions) target.conditions = [];

  if (result === 'critical-success') {
    target.conditions.push({ name: 'fascinated', duration: 'permanent', value: 1, source: `fascperf-${actor.id}` });
    message += `\n✨ ${target.name} is **fascinated** until the performance ends! Can\'t use hostile actions.`;
  } else if (result === 'success') {
    target.conditions.push({ name: 'fascinated', duration: 1, value: 1, source: `fascperf-${actor.id}` });
    message += `\n✅ ${target.name} is **fascinated** for 1 round!`;
  } else {
    message += `\n❌ ${target.name} is unimpressed.`;
  }

  if (heroPointMessage) message += `\n${heroPointMessage}`;
  return { success: true, message, details: { d20: finalD20, performanceBonus, total, willDC, result } };
}

