export function resolveIntimidatingGlare(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Intimidating Glare')) {
    return { success: false, message: `${actor.name} does not have Intimidating Glare.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (!targetId) return { success: false, message: 'No target specified for Intimidating Glare.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target || target.currentHealth <= 0) {
    return { success: false, message: 'Target not found or is unconscious.', errorCode: 'TARGET_NOT_FOUND' };
  }

  // Demoralize using visual trait instead of auditory — no language barrier
  const intimidationBonus = ctx.getSkillBonus(actor, 'intimidation');
  const willDC = ctx.getWillDC(target);
  const d20 = rollD20();
  let total = d20 + intimidationBonus;
  let finalD20 = d20;
  let heroPointMessage: string | undefined;

  if (heroPointsSpent && heroPointsSpent > 0) {
    const spendResult = ctx.spendHeroPoints(actor, heroPointsSpent, { d20, bonus: intimidationBonus, total, result: 'pending' });
    if (spendResult.success && spendResult.newRoll) {
      finalD20 = spendResult.newRoll.d20;
      total = spendResult.newRoll.total;
      heroPointMessage = spendResult.message;
    }
  }

  const result = getDegreeOfSuccess(finalD20, total, willDC);
  let message = `😠 ${actor.name} glares menacingly at ${target.name}! (Visual, no language needed)\n`;
  message += `Intimidation: ${finalD20} + ${intimidationBonus} = ${total} vs Will DC ${willDC}\n`;
  message += `Result: **${result.toUpperCase()}**`;

  if (!target.conditions) target.conditions = [];

  if (result === 'critical-success') {
    target.conditions.push({ name: 'frightened', duration: 2, value: 2 });
    message += `\n✨ ${target.name} is **frightened 2**!`;
  } else if (result === 'success') {
    target.conditions.push({ name: 'frightened', duration: 1, value: 1 });
    message += `\n✅ ${target.name} is **frightened 1**!`;
  } else {
    message += `\n❌ No effect.`;
  }

  if (heroPointMessage) message += `\n${heroPointMessage}`;
  return { success: true, message, details: { d20: finalD20, intimidationBonus, total, willDC, result } };
}

