export function resolveLieToMe(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Lie to Me')) {
    return { success: false, message: `${actor.name} does not have Lie to Me.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target || target.currentHealth <= 0) {
    return { success: false, message: 'Target not found or is unconscious.', errorCode: 'TARGET_NOT_FOUND' };
  }

  // Use Deception to detect lies (passive Deception DC as the threshold)
  const deceptionBonus = ctx.getSkillBonus(actor, 'deception');
  const targetDeceptionDC = 10 + ctx.getSkillBonus(target, 'deception');
  const d20 = rollD20();
  let total = d20 + deceptionBonus;
  let finalD20 = d20;
  let heroPointMessage: string | undefined;

  if (heroPointsSpent && heroPointsSpent > 0) {
    const spendResult = ctx.spendHeroPoints(actor, heroPointsSpent, { d20, bonus: deceptionBonus, total, result: 'pending' });
    if (spendResult.success && spendResult.newRoll) {
      finalD20 = spendResult.newRoll.d20;
      total = spendResult.newRoll.total;
      heroPointMessage = spendResult.message;
    }
  }

  const result = getDegreeOfSuccess(finalD20, total, targetDeceptionDC);
  let message = `🔍 ${actor.name} uses Lie to Me on ${target.name}!\n`;
  message += `Deception: ${finalD20} + ${deceptionBonus} = ${total} vs Deception DC ${targetDeceptionDC}\n`;
  message += `Result: **${result.toUpperCase()}**`;

  if (result === 'critical-success') {
    message += `\n✨ ${actor.name} knows exactly which statements were lies and the general topic of each!`;
  } else if (result === 'success') {
    message += `\n✅ ${actor.name} can tell ${target.name} was lying but not which statements specifically.`;
  } else if (result === 'critical-failure') {
    message += `\n💥 ${actor.name} believes the lies were true!`;
  } else {
    message += `\n❌ ${actor.name} can't tell if ${target.name} is being truthful or not.`;
  }

  if (heroPointMessage) message += `\n${heroPointMessage}`;
  return { success: true, message, details: { d20: finalD20, deceptionBonus, total, targetDeceptionDC, result } };
}

