export function resolvePickpocket(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Pickpocket')) {
    return { success: false, message: `${actor.name} does not have Pickpocket.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target || target.currentHealth <= 0) {
    return { success: false, message: 'Target not found or is unconscious.', errorCode: 'TARGET_NOT_FOUND' };
  }

  // Pickpocket: Steal from creatures who are observing you (no -5 penalty)
  const thieveryBonus = ctx.getSkillBonus(actor, 'thievery');
  const perceptionDC = ctx.getPerceptionDC(target);
  const d20 = rollD20();
  let total = d20 + thieveryBonus;
  let finalD20 = d20;
  let heroPointMessage: string | undefined;

  if (heroPointsSpent && heroPointsSpent > 0) {
    const spendResult = ctx.spendHeroPoints(actor, heroPointsSpent, { d20, bonus: thieveryBonus, total, result: 'pending' });
    if (spendResult.success && spendResult.newRoll) {
      finalD20 = spendResult.newRoll.d20;
      total = spendResult.newRoll.total;
      heroPointMessage = spendResult.message;
    }
  }

  const result = getDegreeOfSuccess(finalD20, total, perceptionDC);
  let message = `🤏 ${actor.name} attempts to pickpocket ${target.name}!\n`;
  message += `Thievery: ${finalD20} + ${thieveryBonus} = ${total} vs Perception DC ${perceptionDC}\n`;
  message += `Result: **${result.toUpperCase()}**`;

  if (result === 'critical-success') {
    message += `\n✨ ${actor.name} steals an item from ${target.name} without them noticing!`;
  } else if (result === 'success') {
    message += `\n✅ ${actor.name} steals an item from ${target.name}!`;
  } else if (result === 'critical-failure') {
    message += `\n🚨 ${target.name} catches ${actor.name} in the act and becomes hostile!`;
  } else {
    message += `\n❌ ${actor.name} fails to steal anything.`;
  }

  if (heroPointMessage) message += `\n${heroPointMessage}`;
  return { success: true, message, details: { d20: finalD20, thieveryBonus, total, perceptionDC, result } };
}

