export function resolveRiskySurgery(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Risky Surgery')) {
    return { success: false, message: `${actor.name} does not have Risky Surgery.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : actor;
  if (!target || target.currentHealth <= 0) {
    return { success: false, message: 'Target not found or is unconscious.', errorCode: 'TARGET_NOT_FOUND' };
  }

  // Deal 1d8 slashing damage to the target, then get +2 circumstance bonus to Treat Wounds check
  const surgeryDamage = rollDamageFormula('1d8');
  target.currentHealth = Math.max(0, target.currentHealth - surgeryDamage);

  const medicineBonus = ctx.getSkillBonus(actor, 'medicine') + 2; // +2 circumstance
  const dc = 15;
  const d20 = rollD20();
  let total = d20 + medicineBonus;
  let finalD20 = d20;
  let heroPointMessage: string | undefined;

  if (heroPointsSpent && heroPointsSpent > 0) {
    const spendResult = ctx.spendHeroPoints(actor, heroPointsSpent, { d20, bonus: medicineBonus, total, result: 'pending' });
    if (spendResult.success && spendResult.newRoll) {
      finalD20 = spendResult.newRoll.d20;
      total = spendResult.newRoll.total;
      heroPointMessage = spendResult.message;
    }
  }

  const result = getDegreeOfSuccess(finalD20, total, dc);
  let message = `🩸 ${actor.name} performs Risky Surgery on ${target.name}!\n`;
  message += `Surgery damage: ${surgeryDamage} slashing (HP: ${target.currentHealth}/${target.maxHealth})\n`;
  message += `Medicine (+2 circ): ${finalD20} + ${medicineBonus} = ${total} vs DC ${dc}\n`;
  message += `Result: **${result.toUpperCase()}**`;

  let healing = 0;
  if (result === 'critical-success') {
    healing = rollDamageFormula('4d8');
    target.currentHealth = Math.min(target.maxHealth, target.currentHealth + healing);
    message += `\n✨ Critical! ${target.name} heals ${healing} HP! (HP: ${target.currentHealth}/${target.maxHealth})`;
  } else if (result === 'success') {
    healing = rollDamageFormula('2d8');
    target.currentHealth = Math.min(target.maxHealth, target.currentHealth + healing);
    message += `\n✅ ${target.name} heals ${healing} HP! (HP: ${target.currentHealth}/${target.maxHealth})`;
  } else if (result === 'critical-failure') {
    const damage = rollDamageFormula('1d8');
    target.currentHealth = Math.max(0, target.currentHealth - damage);
    message += `\n💥 Critical failure! ${target.name} takes ${damage} additional damage! (HP: ${target.currentHealth}/${target.maxHealth})`;
  } else {
    message += `\n❌ No healing.`;
  }

  if (heroPointMessage) message += `\n${heroPointMessage}`;
  return { success: true, message, details: { d20: finalD20, medicineBonus, total, dc, result, healing, surgeryDamage } };
}

