export function resolveDistractingPerformance(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Distracting Performance')) {
    return { success: false, message: `${actor.name} does not have Distracting Performance.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  // Use Performance for Create a Diversion instead of Deception
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target || target.currentHealth <= 0) {
    return { success: false, message: 'Target not found or is unconscious.', errorCode: 'TARGET_NOT_FOUND' };
  }

  const performanceBonus = ctx.getSkillBonus(actor, 'performance');
  const perceptionDC = ctx.getPerceptionDC(target);
  const d20 = rollD20();
  let total = d20 + performanceBonus;
  let finalD20 = d20;
  let heroPointMessage: string | undefined;

  if (heroPointsSpent && heroPointsSpent > 0) {
    const spendResult = ctx.spendHeroPoints(actor, heroPointsSpent, { d20, bonus: performanceBonus, total, result: 'pending' });
    if (spendResult.success && spendResult.newRoll) {
      finalD20 = spendResult.newRoll.d20;
      total = spendResult.newRoll.total;
      heroPointMessage = spendResult.message;
    }
  }

  const result = getDegreeOfSuccess(finalD20, total, perceptionDC);
  let message = `🎶 ${actor.name} uses Distracting Performance against ${target.name}!\n`;
  message += `Performance: ${finalD20} + ${performanceBonus} = ${total} vs Perception DC ${perceptionDC}\n`;
  message += `Result: **${result.toUpperCase()}**`;

  if (result === 'critical-success' || result === 'success') {
    message += `\n✅ ${actor.name} becomes hidden from ${target.name}!`;
  } else {
    message += `\n❌ ${target.name} sees through the performance.`;
  }

  if (heroPointMessage) message += `\n${heroPointMessage}`;
  return { success: true, message, details: { d20: finalD20, performanceBonus, total, perceptionDC, result } };
}

export function resolveEncouragingWords(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Encouraging Words')) {
    return { success: false, message: `${actor.name} does not have Encouraging Words.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target || target.currentHealth <= 0) {
    return { success: false, message: 'Target not found or is unconscious.', errorCode: 'TARGET_NOT_FOUND' };
  }

  // 1 action: Diplomacy check to heal an ally with words of encouragement
  const diplomacyBonus = ctx.getSkillBonus(actor, 'diplomacy');
  const dc = 15 + target.level; // DC scales with target level
  const d20 = rollD20();
  let total = d20 + diplomacyBonus;
  let finalD20 = d20;
  let heroPointMessage: string | undefined;

  if (heroPointsSpent && heroPointsSpent > 0) {
    const spendResult = ctx.spendHeroPoints(actor, heroPointsSpent, { d20, bonus: diplomacyBonus, total, result: 'pending' });
    if (spendResult.success && spendResult.newRoll) {
      finalD20 = spendResult.newRoll.d20;
      total = spendResult.newRoll.total;
      heroPointMessage = spendResult.message;
    }
  }

  const result = getDegreeOfSuccess(finalD20, total, dc);
  let message = `💬 ${actor.name} speaks encouraging words to ${target.name}!\n`;
  message += `Diplomacy: ${finalD20} + ${diplomacyBonus} = ${total} vs DC ${dc}\n`;
  message += `Result: **${result.toUpperCase()}**`;

  let healing = 0;
  if (result === 'critical-success') {
    healing = rollDamageFormula('2d8') + diplomacyBonus;
    target.currentHealth = Math.min(target.maxHealth, target.currentHealth + healing);
    message += `\n✨ ${target.name} heals ${healing} HP! (HP: ${target.currentHealth}/${target.maxHealth})`;
  } else if (result === 'success') {
    healing = rollDamageFormula('1d8') + Math.floor(diplomacyBonus / 2);
    target.currentHealth = Math.min(target.maxHealth, target.currentHealth + healing);
    message += `\n✅ ${target.name} heals ${healing} HP! (HP: ${target.currentHealth}/${target.maxHealth})`;
  } else if (result === 'critical-failure') {
    message += `\n💥 ${target.name} can't benefit from Encouraging Words for 1 hour!`;
  } else {
    message += `\n❌ No effect.`;
  }

  if (heroPointMessage) message += `\n${heroPointMessage}`;
  return { success: true, message, details: { d20: finalD20, diplomacyBonus, total, dc, result, healing } };
}

