export function resolveAdvancedFirstAid(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Advanced First Aid')) {
    return { success: false, message: `${actor.name} does not have Advanced First Aid.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : actor;
  if (!target) {
    return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };
  }

  // 1 action: Stop persistent bleed damage or stabilize a dying creature with +2 bonus
  const medicineBonus = ctx.getSkillBonus(actor, 'medicine') + 2; // circumstance bonus from Advanced
  const dc = 15;
  const d20 = rollD20();
  let total = d20 + medicineBonus;
  let finalD20 = d20;
  let heroPointMessage: string | undefined;

  if (heroPointsSpent && heroPointsSpent > 0) {
    const spendResult = ctx.spendHeroPoints(actor, heroPointsSpent, { d20, bonus: medicineBonus, total, result: 'pending' });
    if (spendResult.success && spendResult.newRoll) {
      finalD20 = spendResult.newRoll.d20;
      total = spendResult.newRoll.total;
      heroPointMessage = spendResult.message;
    }
  }

  const result = getDegreeOfSuccess(finalD20, total, dc);
  let message = `🏥 ${actor.name} performs Advanced First Aid on ${target.name}!\n`;
  message += `Medicine (+2 circ): ${finalD20} + ${medicineBonus} = ${total} vs DC ${dc}\n`;
  message += `Result: **${result.toUpperCase()}**`;

  if (!target.conditions) target.conditions = [];

  if (result === 'critical-success' || result === 'success') {
    // Remove persistent bleed if present
    const bleedIndex = target.conditions.findIndex(c => c.name === 'persistent-bleed' || c.name === 'persistent-damage');
    if (bleedIndex >= 0) {
      target.conditions.splice(bleedIndex, 1);
      message += `\n✅ Stopped ${target.name}'s persistent bleed damage!`;
    }
    // Stabilize if dying
    const dyingIndex = target.conditions.findIndex(c => c.name === 'dying');
    if (dyingIndex >= 0) {
      target.conditions.splice(dyingIndex, 1);
      message += `\n✅ ${target.name} is stabilized!`;
    }
    if (bleedIndex < 0 && dyingIndex < 0) {
      message += `\n✅ First aid applied (no bleed or dying to treat).`;
    }
  } else {
    message += `\n❌ Failed to administer first aid.`;
  }

  if (heroPointMessage) message += `\n${heroPointMessage}`;
  return { success: true, message, details: { d20: finalD20, medicineBonus, total, dc, result } };
}

