export function resolveDisturbingKnowledge(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Disturbing Knowledge')) {
    return { success: false, message: `${actor.name} does not have Disturbing Knowledge.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target || target.currentHealth <= 0) {
    return { success: false, message: 'Target not found or is unconscious.', errorCode: 'TARGET_NOT_FOUND' };
  }

  // 1 action: Occultism check vs target's Will DC. Success: target is frightened 1 + stupefied 1
  const occultismBonus = ctx.getSkillBonus(actor, 'occultism');
  const willDC = ctx.getWillDC(target);
  const d20 = rollD20();
  let total = d20 + occultismBonus;
  let finalD20 = d20;
  let heroPointMessage: string | undefined;

  if (heroPointsSpent && heroPointsSpent > 0) {
    const spendResult = ctx.spendHeroPoints(actor, heroPointsSpent, { d20, bonus: occultismBonus, total, result: 'pending' });
    if (spendResult.success && spendResult.newRoll) {
      finalD20 = spendResult.newRoll.d20;
      total = spendResult.newRoll.total;
      heroPointMessage = spendResult.message;
    }
  }

  const result = getDegreeOfSuccess(finalD20, total, willDC);
  let message = `👻 ${actor.name} shares disturbing knowledge with ${target.name}!\n`;
  message += `Occultism: ${finalD20} + ${occultismBonus} = ${total} vs Will DC ${willDC}\n`;
  message += `Result: **${result.toUpperCase()}**`;

  if (!target.conditions) target.conditions = [];

  if (result === 'critical-success') {
    target.conditions.push({ name: 'frightened', duration: 2, value: 2 });
    target.conditions.push({ name: 'stupefied', duration: 2, value: 1 });
    message += `\n✨ ${target.name} is **frightened 2** and **stupefied 1** for 2 rounds!`;
  } else if (result === 'success') {
    target.conditions.push({ name: 'frightened', duration: 1, value: 1 });
    target.conditions.push({ name: 'stupefied', duration: 1, value: 1 });
    message += `\n✅ ${target.name} is **frightened 1** and **stupefied 1** for 1 round!`;
  } else {
    message += `\n❌ ${target.name} is unaffected by the disturbing knowledge.`;
  }

  if (heroPointMessage) message += `\n${heroPointMessage}`;
  return { success: true, message, details: { d20: finalD20, occultismBonus, total, willDC, result } };
}

