export function resolveEvangelize(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Evangelize')) {
    return { success: false, message: `${actor.name} does not have Evangelize.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target || target.currentHealth <= 0) {
    return { success: false, message: 'Target not found or is unconscious.', errorCode: 'TARGET_NOT_FOUND' };
  }

  // 1 action: Diplomacy check vs Will DC. Success: target is stupefied 1 (or fascinated on crit)
  const diplomacyBonus = ctx.getSkillBonus(actor, 'diplomacy');
  const willDC = ctx.getWillDC(target);
  const d20 = rollD20();
  let total = d20 + diplomacyBonus;
  let finalD20 = d20;
  let heroPointMessage: string | undefined;

  if (heroPointsSpent && heroPointsSpent > 0) {
    const spendResult = ctx.spendHeroPoints(actor, heroPointsSpent, { d20, bonus: diplomacyBonus, total, result: 'pending' });
    if (spendResult.success && spendResult.newRoll) {
      finalD20 = spendResult.newRoll.d20;
      total = spendResult.newRoll.total;
      heroPointMessage = spendResult.message;
    }
  }

  const result = getDegreeOfSuccess(finalD20, total, willDC);
  let message = `✨ ${actor.name} evangelizes to ${target.name}!\n`;
  message += `Diplomacy: ${finalD20} + ${diplomacyBonus} = ${total} vs Will DC ${willDC}\n`;
  message += `Result: **${result.toUpperCase()}**`;

  if (!target.conditions) target.conditions = [];

  if (result === 'critical-success') {
    target.conditions.push({ name: 'fascinated', duration: 'permanent', value: 1, source: `evangelize-${actor.id}` });
    message += `\n✨ ${target.name} is **fascinated** by ${actor.name}'s words!`;
  } else if (result === 'success') {
    target.conditions.push({ name: 'stupefied', duration: 1, value: 1, source: `evangelize-${actor.id}` });
    message += `\n✅ ${target.name} is **stupefied 1** for 1 round from the impassioned rhetoric!`;
  } else {
    message += `\n❌ ${target.name} is unmoved.`;
  }

  if (heroPointMessage) message += `\n${heroPointMessage}`;
  return { success: true, message, details: { d20: finalD20, diplomacyBonus, total, willDC, result } };
}

