export function resolveParagonBattleMedicine(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Paragon Battle Medicine')) {
    return { success: false, message: `${actor.name} does not have Paragon Battle Medicine.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : actor;
  if (!target || target.currentHealth <= 0) {
    return { success: false, message: 'Target not found or is unconscious.', errorCode: 'TARGET_NOT_FOUND' };
  }

  // Like Battle Medicine but with expert-level healing (higher dice)
  const medicineBonus = ctx.getSkillBonus(actor, 'medicine');
  const dc = 20; // Expert DC
  const d20 = rollD20();
  let total = d20 + medicineBonus;
  let finalD20 = d20;
  let heroPointMessage: string | undefined;

  if (heroPointsSpent && heroPointsSpent > 0) {
    const spendResult = ctx.spendHeroPoints(actor, heroPointsSpent, { d20, bonus: medicineBonus, total, result: 'pending' });
    if (spendResult.success && spendResult.newRoll) {
      finalD20 = spendResult.newRoll.d20;
      total = spendResult.newRoll.total;
      heroPointMessage = spendResult.message;
    }
  }

  const result = getDegreeOfSuccess(finalD20, total, dc);
  let message = `⚕️ ${actor.name} uses Paragon Battle Medicine on ${target.name}!\n`;
  message += `Medicine: ${finalD20} + ${medicineBonus} = ${total} vs DC ${dc}\n`;
  message += `Result: **${result.toUpperCase()}**`;

  let healing = 0;
  if (result === 'critical-success') {
    healing = rollDamageFormula('4d8') + 10;
    target.currentHealth = Math.min(target.maxHealth, target.currentHealth + healing);
    message += `\n✨ Critical! ${target.name} heals ${healing} HP! (HP: ${target.currentHealth}/${target.maxHealth})`;
  } else if (result === 'success') {
    healing = rollDamageFormula('2d8') + 10;
    target.currentHealth = Math.min(target.maxHealth, target.currentHealth + healing);
    message += `\n✅ ${target.name} heals ${healing} HP! (HP: ${target.currentHealth}/${target.maxHealth})`;
  } else if (result === 'critical-failure') {
    const damage = rollDamageFormula('1d8');
    target.currentHealth = Math.max(0, target.currentHealth - damage);
    message += `\n💥 Critical failure! ${target.name} takes ${damage} damage! (HP: ${target.currentHealth}/${target.maxHealth})`;
  } else {
    message += `\n❌ No effect.`;
  }

  if (heroPointMessage) message += `\n${heroPointMessage}`;
  return { success: true, message, details: { d20: finalD20, medicineBonus, total, dc, result, healing } };
}

