export function resolveScareToDeath(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string, heroPointsSpent?: number): ActionResult {
  if (!ctx.hasFeat(actor, 'Scare to Death')) {
    return { success: false, message: `${actor.name} does not have Scare to Death.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  if (!targetId) return { success: false, message: 'No target specified.', errorCode: 'NO_TARGET' };
  const target = gameState.creatures.find(c => c.id === targetId);
  if (!target || target.currentHealth <= 0) {
    return { success: false, message: 'Target not found or is unconscious.', errorCode: 'TARGET_NOT_FOUND' };
  }

  // Legendary Intimidation: 1 action, target makes Will save or suffers terribly
  const intimidationDC = 10 + ctx.getSkillBonus(actor, 'intimidation');
  const d20 = rollD20();
  const willBonus = calculateSaveBonus(target, 'will');
  const total = d20 + willBonus;

  const result = getDegreeOfSuccess(d20, total, intimidationDC);
  let message = `💀 ${actor.name} attempts to Scare ${target.name} to Death!\n`;
  message += `${target.name} Will: ${d20} + ${willBonus} = ${total} vs Intimidation DC ${intimidationDC}\n`;
  message += `Result: **${result.toUpperCase()}** (target's save)`;

  if (!target.conditions) target.conditions = [];

  if (result === 'critical-failure') {
    target.currentHealth = 0;
    initDying(target, gameState);
    message += `\n☠️ ${target.name} is so frightened they DROP TO 0 HP!`;
  } else if (result === 'failure') {
    target.conditions.push({ name: 'frightened', duration: 2, value: 2 });
    message += `\n😱 ${target.name} is **frightened 2**!`;
  } else if (result === 'success') {
    target.conditions.push({ name: 'frightened', duration: 1, value: 1 });
    message += `\n✅ ${target.name} is **frightened 1**.`;
  } else {
    message += `\n🛡️ ${target.name} is immune to ${actor.name}'s Scare to Death for 1 minute!`;
  }

  return { success: true, message, details: { d20, willBonus, total, intimidationDC, result } };
}

