export function resolveLegendaryMedic(ctx: FeatActionContext, actor: Creature, gameState: GameState, targetId?: string): ActionResult {
  if (!ctx.hasFeat(actor, 'Legendary Medic')) {
    return { success: false, message: `${actor.name} does not have Legendary Medic.`, errorCode: 'FEAT_NOT_AVAILABLE' };
  }
  const target = targetId ? gameState.creatures.find(c => c.id === targetId) : actor;
  if (!target) {
    return { success: false, message: 'Target not found.', errorCode: 'TARGET_NOT_FOUND' };
  }
  // Legendary Medicine: 1 hour to remove disease, drain, or blindness/deafness
  // DC 30 Medicine check
  const medicineBonus = ctx.getSkillBonus(actor, 'medicine');
  const dc = 30;
  const d20 = rollD20();
  const total = d20 + medicineBonus;
  const result = getDegreeOfSuccess(d20, total, dc);

  let message = `🏅 ${actor.name} performs legendary medical treatment on ${target.name}!\n`;
  message += `Medicine: ${d20} + ${medicineBonus} = ${total} vs DC ${dc}\n`;
  message += `Result: **${result.toUpperCase()}**`;

  if (!target.conditions) target.conditions = [];

  if (result === 'critical-success' || result === 'success') {
    // Remove disease, drain, or sensory conditions
    const removable = ['disease', 'drained', 'blinded', 'deafened'];
    const removed = target.conditions.filter(c => removable.includes(c.name));
    target.conditions = target.conditions.filter(c => !removable.includes(c.name));
    if (removed.length > 0) {
      message += `\n✨ Removed: ${removed.map(c => c.name).join(', ')} from ${target.name}!`;
    } else {
      message += `\n✅ Treatment successful (no removable conditions found).`;
    }
  } else {
    message += `\n❌ Treatment failed.`;
  }

  return { success: true, message, details: { d20, medicineBonus, total, dc, result } };
}

